globalThis.__BQ = {"govdeDikot":{"ilkokul":{"kolay":[{"q":"Çift çenekli bir bitkinin gövdesini enine kestiğimizde, dış yüzeyi örten ince ve koruyucu tabakaya ne ad verilir?","steps":[{"t":"Gövdeyi inceleyelim","a":"En dışta koruyucu bir örtü var","d":"Bir bitki gövdesini ortadan ikiye kestiğimizde halkalar gibi tabakalar görürüz. En dışta gövdeyi saran ince bir örtü tabakası bulunur. Bu tabaka gövdenin iç kısmını korur."},{"t":"Örtü tabakasının adı","a":"Bu tabaka epidermistir","d":"Gövdenin en dışındaki bu koruyucu örtüye epidermis denir. Epidermis, gövdenin içindeki nazik kısımları dış etkilerden ve su kaybından korur."}],"ans":"Epidermis (üst deri)"},{"q":"Bitki gövdesinin temel görevlerinden biri nedir? Gövde bitkiyi nasıl ayakta tutar?","steps":[{"t":"Gövdenin işine bakalım","a":"Gövde bitkiyi taşır","d":"Gövde, bitkinin yapraklarını, çiçeklerini ve meyvelerini taşıyan dik kısımdır. Bir bitkide gövde olmasaydı yapraklar yere yığılırdı."},{"t":"Dik durma görevi","a":"Gövde bitkiyi dik tutar","d":"Gövde sağlam yapısı sayesinde bitkiyi dik tutar ve yaprakların güneş ışığına ulaşmasını sağlar. Böylece bitki büyür ve gelişir."}],"ans":"Gövde bitkiyi dik tutar ve yaprakları, çiçekleri taşır."},{"q":"Çift çenekli bitki gövdesinde su ve mineralleri kökten yapraklara taşıyan borular vardır. Bu taşıma borularının olduğu kısma genel olarak ne deriz?","steps":[{"t":"Suyun yolculuğu","a":"Su kökten yukarı çıkar","d":"Bitki, topraktaki suyu kökleriyle alır. Bu suyun yapraklara ulaşması için gövdenin içinde ince borular bulunur. Bu borular suyu yukarı taşır."},{"t":"Taşıma borularının yeri","a":"Borular iletim demetidir","d":"Su ve mineralleri taşıyan bu borulara iletim borusu denir ve bunlar bir arada bulunarak iletim demeti oluşturur. İletim demetleri gövdede taşıma görevini yapar."}],"ans":"İletim demetleri (taşıma boruları)"},{"q":"Bir ağacın gövdesi neden serttir ve elimizle kolayca bükülmez?","steps":[{"t":"Gövdeyi yoklayalım","a":"Gövde sert ve dayanıklıdır","d":"Ağaç gövdesini elimizle bükmeye çalıştığımızda bükülmediğini görürüz. Gövde çok sağlam ve dayanıklı bir yapıya sahiptir."},{"t":"Sertliğin nedeni","a":"İçinde destek dokular var","d":"Gövdenin içinde bitkiyi dik tutan ve ona destek veren sert dokular bulunur. Bu destek dokuları gövdeyi sertleştirir ve ağacın yıllarca ayakta kalmasını sağlar."}],"ans":"Gövdesinde destek veren sert dokular bulunduğu için serttir."},{"q":"Çift çenekli bir bitkinin gövdesini enine kestiğimizde tam ortada yumuşak bir bölge görürüz. Gövdenin tam merkezindeki bu yumuşak kısma ne denir?","steps":[{"t":"Gövdenin ortası","a":"Tam ortada yumuşak bölge var","d":"Gövdeyi enine kestiğimizde tam ortada diğer kısımlardan daha yumuşak bir bölge görürüz. Bu bölge gövdenin merkezinde bulunur."},{"t":"Merkezin adı","a":"Bu bölge özdür","d":"Gövdenin tam ortasındaki bu yumuşak bölgeye öz denir. Öz, bitkide besin depolama gibi görevler yapar."}],"ans":"Öz"}],"zor":[{"q":"Çift çenekli bir bitki gövdesinde, koruyucu dış örtünün hemen altında kalan ve depo görevi de yapabilen geniş bölgeye ne ad verilir?","steps":[{"t":"Örtünün altı","a":"Epidermisin altında geniş bir bölge var","d":"Gövdenin en dışında epidermis adı verilen koruyucu örtü bulunur. Bu örtünün hemen altında daha geniş ve yumuşak bir bölge yer alır."},{"t":"Bu bölgenin görevi","a":"Burada besin depolanabilir","d":"Epidermisin altındaki bu geniş bölgeye korteks denir. Korteks bitkiye destek olur ve içinde besin depolanabilir."}],"ans":"Korteks (kabuk)"},{"q":"Çift çenekli bir ağaç her yıl gövdesini kalınlaştırarak büyür. Bir ağaç gövdesinin yıllar geçtikçe kalınlaşmasının nedeni nedir?","steps":[{"t":"Ağacın büyümesi","a":"Ağaç her yıl kalınlaşır","d":"Genç bir fidan ince bir gövdeye sahipken, yıllar geçtikçe gövdesi giderek kalınlaşır. Yaşlı ağaçların gövdeleri çok kalın olur."},{"t":"Kalınlaşmanın nedeni","a":"Gövdeye her yıl yeni tabaka eklenir","d":"Çift çenekli ağaçların gövdesinde her yıl yeni hücre tabakaları eklenir. Bu sayede gövde her geçen yıl biraz daha kalınlaşır ve enine büyür."}],"ans":"Gövdeye her yıl yeni tabakalar eklendiği için kalınlaşır."},{"q":"Çift çenekli bir bitki gövdesinde su yukarı taşınırken, yapraklarda yapılan besin de aşağıya taşınır. Gövdede iki farklı yönde iki farklı taşıma olmasının nedeni nedir?","steps":[{"t":"İki taşıma yönü","a":"Hem su yukarı hem besin aşağı taşınır","d":"Bitki gövdesinde su ve mineraller kökten yapraklara doğru yukarı taşınır. Aynı zamanda yapraklarda yapılan besin gövde boyunca aşağıya taşınır."},{"t":"İki farklı boru","a":"İki ayrı taşıma borusu vardır","d":"Bu iki farklı taşıma için gövdede iki ayrı boru sistemi bulunur. Biri suyu taşırken diğeri besini taşır, böylece taşıma karışmaz."}],"ans":"Su ve besin için iki ayrı taşıma borusu bulunduğu için iki yönde taşıma olur."},{"q":"Çift çenekli bir bitki gövdesini enine kestiğimizde taşıma boruları gelişigüzel dağılmış mıdır, yoksa düzenli bir biçimde mi yerleşmiştir?","steps":[{"t":"Boruların yerine bakalım","a":"Borular belirli bir düzende","d":"Çift çenekli bir gövdeyi enine kestiğimizde taşıma borularının dağınık değil, belirli bir düzene göre yerleştiğini görürüz."},{"t":"Düzenin şekli","a":"Borular halka gibi sıralanır","d":"Bu taşıma boruları gövdenin içinde yuvarlak bir halka biçiminde sıralanır. Bu düzenli halka, çift çenekli bitkilerin önemli bir özelliğidir."}],"ans":"Taşıma boruları düzenli bir halka şeklinde sıralanır."},{"q":"Çift çenekli bir bitkinin gövdesinde, öz bölgesinden dışarıya, korteks bölgesine doğru uzanan ışınsal hatlar görülür. Özden dışa doğru uzanan bu yapılara ne denir?","steps":[{"t":"Özden dışa hatlar","a":"Özden dışa doğru çizgiler uzanır","d":"Gövdeyi enine kestiğimizde, tam ortadaki özden dışarıya doğru ince çizgiler halinde uzanan yapılar görürüz. Bunlar tekerlek parmakları gibi merkezden dışa doğru gider."},{"t":"Bu hatların adı","a":"Bunlar öz kollarıdır","d":"Özden dışa doğru uzanan bu ışınsal hatlara öz kolları denir. Öz kolları gövdede su ve besinin yanlara doğru taşınmasına yardımcı olur."}],"ans":"Öz kolları (öz ışınları)"}]},"ortaokul":{"kolay":[{"q":"Çift çenekli (dikot) bir bitkinin gövdesinde, en dıştan içe doğru ilk üç tabaka sırasıyla hangileridir?","steps":[{"t":"En dış tabaka","a":"En dışta epidermis vardır","d":"Dikot gövdenin enine kesitinde en dışta koruyucu bir tek hücre sırası bulunur. Bu tabaka epidermistir ve gövdeyi dış etkilerden korur."},{"t":"Epidermisin altı","a":"Altında korteks bulunur","d":"Epidermisin hemen altında korteks adı verilen geniş bir parankima dokusu yer alır. Korteks destek sağlar ve besin depolayabilir."},{"t":"Korteksin içi","a":"İçte iletim demetleri vardır","d":"Korteksin içinde su ve besin taşıyan iletim demetleri bulunur. Böylece dıştan içe sıralama epidermis, korteks ve iletim demetleri şeklindedir."}],"ans":"Epidermis, korteks, iletim demetleri"},{"q":"Dikot gövdede su ve mineralleri taşıyan dokuya ksilem, yapraklarda üretilen besini taşıyan dokuya ne ad verilir?","steps":[{"t":"Su taşıyan doku","a":"Su ve mineralleri ksilem taşır","d":"Dikot gövdede kökten alınan su ve mineraller yukarıya doğru taşınır. Bu taşımayı ksilem (odun borusu) dokusu yapar."},{"t":"Besin taşıyan doku","a":"Besini floem taşır","d":"Yapraklarda fotosentezle üretilen besin gövde boyunca taşınır. Bu organik besini taşıyan dokuya floem (soymuk borusu) denir."}],"ans":"Floem (soymuk borusu)"},{"q":"Bir dikot iletim demetinde ksilem ve floemin gövde içindeki konumları nasıldır? Hangisi içte, hangisi dışta bulunur?","steps":[{"t":"Demetin yapısı","a":"Demette iki doku bir arada","d":"Dikot gövdede iletim demetleri içinde ksilem ve floem birlikte bulunur. Bunların demet içindeki konumu belirli bir düzene göredir."},{"t":"İçte ve dışta olanlar","a":"Ksilem içte, floem dışta","d":"İletim demetinde ksilem gövdenin merkezine yani içe doğru, floem ise dış yüzeye yani dışa doğru konumlanır. Bu düzen dikot gövdeler için tipiktir."}],"ans":"Ksilem içte, floem dışta bulunur."},{"q":"Dikot bir gövdenin enine kesitinde iletim demetleri nasıl bir düzende dizilir?","steps":[{"t":"Demetlerin konumu","a":"Demetler düzenlidir","d":"Dikot gövdeyi enine kestiğimizde iletim demetlerinin rastgele değil, düzenli bir şekilde sıralandığını görürüz. Bu düzen gözle ayırt edilebilir."},{"t":"Dizilim şekli","a":"Halka biçiminde dizilir","d":"İletim demetleri gövde merkezinin çevresinde tek bir halka oluşturacak şekilde dizilir. Bu düzenli halka dizilimi dikotların ayırt edici özelliğidir."}],"ans":"İletim demetleri düzenli bir halka şeklinde dizilir."},{"q":"Dikot gövdenin merkezinde bulunan ve genellikle parankima hücrelerinden oluşan depo bölgesine ne ad verilir?","steps":[{"t":"Gövdenin merkezi","a":"Merkezde bir bölge var","d":"Dikot gövdenin enine kesitinde, iletim demetlerinin oluşturduğu halkanın iç tarafında, tam merkezde bir bölge bulunur. Bu bölge yumuşak hücrelerden oluşur."},{"t":"Merkezin görevi","a":"Burada besin depolanır","d":"Merkezdeki bu bölgeye öz denir ve parankima hücrelerinden oluşur. Öz, bitkide su ve besin maddelerinin depolanmasını sağlar."}],"ans":"Öz"}],"zor":[{"q":"Dikot bir iletim demetinde ksilem ile floem arasında ince bir hücre tabakası bulunur. Bu tabakanın adı nedir ve hangi temel görevi yapar?","steps":[{"t":"Demetin ortası","a":"Ksilem ile floem arasında bir tabaka var","d":"Dikot iletim demetinde ksilem içte, floem dışta yer alır. Bu iki dokunun arasında ince bir hücre tabakası bulunur."},{"t":"Tabakanın görevi","a":"Bu tabaka bölünerek büyüme sağlar","d":"Ksilem ile floem arasındaki bu tabakaya demet kambiyumu denir. Kambiyum hücreleri sürekli bölünerek içe ksilem, dışa floem üreterek gövdenin kalınlaşmasını sağlar."}],"ans":"Demet kambiyumu (kambiyum); bölünerek gövdenin enine kalınlaşmasını sağlar."},{"q":"Dikot bitkiler her yıl gövdelerini kalınlaştırabilirken bunu nasıl yaparlar? İkincil (sekonder) büyümeyi sağlayan yapı nedir?","steps":[{"t":"Enine büyüme gözlemi","a":"Dikot gövde her yıl kalınlaşır","d":"Dikot ağaçların gövdeleri yıllar içinde giderek kalınlaşır. Bu enine kalınlaşmaya ikincil (sekonder) büyüme denir."},{"t":"Sorumlu yapı","a":"Kambiyum sürekli bölünür","d":"İkincil büyümeyi demet içindeki ve demetler arasındaki kambiyum sağlar. Kambiyum içe doğru ksilem, dışa doğru floem üreterek gövdeyi her yıl kalınlaştırır."},{"t":"Sonuç","a":"Yıllık halkalar oluşur","d":"Kambiyumun her yıl ürettiği ksilem tabakaları gövdede yıllık halkaları meydana getirir. Bu halkalar sayesinde ağacın yaşı hesaplanabilir."}],"ans":"Kambiyumun sürekli bölünmesiyle ikincil büyüme yaparak kalınlaşırlar."},{"q":"Dikot gövdede öz bölgesinden korteks bölgesine doğru, iletim demetleri arasından geçen ışınsal parankima hatları görülür. Bu yapıların adı nedir ve görevi nelerdir?","steps":[{"t":"Işınsal hatlar","a":"Özden dışa uzanan hatlar var","d":"Dikot gövdenin enine kesitinde, merkezdeki özden korteksdeki kabuğa doğru, iletim demetlerinin arasından ışınsal olarak uzanan hatlar görülür."},{"t":"Yapının adı","a":"Bunlar öz kollarıdır","d":"Bu ışınsal parankima hatlarına öz kolları (öz ışınları) denir. Öz kolları özü korteks ile bağlar."},{"t":"Görevi","a":"Yatay taşıma yaparlar","d":"Öz kolları, su ve besin maddelerinin gövdede merkezden çevreye yani yatay yönde taşınmasını sağlar. Ayrıca besin depolama görevi de yapabilirler."}],"ans":"Öz kolları (öz ışınları); su ve besinin yatay yönde taşınmasını sağlar."},{"q":"Bir dikot gövdesinde demet içindeki ksilem ve floem konumu sabittir. Eğer kambiyum içe ksilem dışa floem üretirse, zamanla gövdedeki odun (ksilem) ve kabuk (floem) miktarları nasıl değişir?","steps":[{"t":"Kambiyumun bölünmesi","a":"Kambiyum iki yöne hücre üretir","d":"Dikot demetinde ksilem içte, floem dıştadır ve aralarında kambiyum bulunur. Kambiyum sürekli bölünerek içe doğru ksilem, dışa doğru floem üretir."},{"t":"Üretim oranı","a":"İçe daha çok ksilem üretilir","d":"Kambiyum genellikle içe doğru daha fazla ksilem üretir. Bu nedenle gövdenin iç kısmında odun dokusu hızla artar."},{"t":"Sonuç","a":"Odun çok, kabuk az olur","d":"Zamanla içte biriken ksilem (odun) gövdenin büyük kısmını oluştururken, dışta üretilen floem daha ince bir kabuk tabakası halinde kalır. Bu yüzden ağaçlarda odun kısmı kabuktan çok daha kalındır."}],"ans":"İçte biriken ksilem (odun) miktarı, dışta kalan floem (kabuk) miktarından çok daha fazla olur."},{"q":"Dikot bir gövdenin epidermisinde bazen mantar doku oluşumu başlar. Yaşlanan dikot gövdelerde epidermisin yerini alan koruyucu yapı nasıl oluşur?","steps":[{"t":"Epidermisin yetersizliği","a":"Gövde kalınlaşınca epidermis yırtılır","d":"Dikot gövde ikincil büyümeyle kalınlaştıkça, tek sıra hücreden oluşan epidermis bu kalınlaşmaya yetişemez ve yırtılmaya başlar. Yeni bir koruyucu örtüye ihtiyaç doğar."},{"t":"Yeni doku oluşumu","a":"Mantar kambiyumu çalışır","d":"Korteks bölgesinde mantar kambiyumu adı verilen bir bölünme dokusu oluşur. Bu kambiyum dışa doğru mantar hücreleri üretir."},{"t":"Sonuç","a":"Periderm oluşur","d":"Üretilen mantar hücreleri ölü ve su geçirmez bir koruyucu tabaka olan peridermi oluşturur. Periderm, yaşlanan gövdede epidermisin yerini alarak koruma görevini üstlenir."}],"ans":"Mantar kambiyumunun ürettiği mantar dokudan oluşan periderm, epidermisin yerini alır."}]},"lise":{"kolay":[{"q":"Dikot bir bitki gövdesinin enine kesitinde, dıştan içe doğru sıralanan temel doku ve bölgeleri yazınız.","steps":[{"t":"Koruyucu doku","a":"En dışta epidermis","d":"Dikot gövdenin en dışında tek sıra hücreden oluşan epidermis bulunur. Epidermis kütikula ile kaplıdır ve su kaybını önler, gövdeyi korur."},{"t":"Temel doku","a":"Altında korteks ve öz","d":"Epidermisin altında korteks yer alır; merkezde ise öz bulunur. Bu parankimatik bölgeler hem destek hem depo görevi yapar."},{"t":"İletim dokusu","a":"Aralarda iletim demetleri","d":"Korteks ile öz arasında iletim demetleri halka biçiminde dizilir. Her demette ksilem içte, floem dışta ve aralarında kambiyum bulunur."}],"ans":"Epidermis, korteks, iletim demetleri (halka şeklinde), öz ve öz kolları."},{"q":"Dikot iletim demetinde ksilem, floem ve kambiyumun konumlarını ve aralarındaki düzeni açıklayınız.","steps":[{"t":"Ksilemin konumu","a":"Ksilem merkeze yakın (içte)","d":"Dikot demetinde ksilem gövdenin merkezine doğru yani içte yer alır. Ksilem su ve mineral taşır, ölü ve kalın çeperli hücrelerden oluşur."},{"t":"Floemin konumu","a":"Floem çevreye yakın (dışta)","d":"Floem demetin dış kısmında, gövde yüzeyine yakın konumlanır. Floem organik besin taşıyan canlı kalburlu borulardan oluşur."},{"t":"Kambiyumun konumu","a":"Arada kambiyum","d":"Ksilem ile floem arasında demet kambiyumu bulunur. Bu meristematik tabaka bölünerek içe ksilem, dışa floem üreterek demeti açık tutar."}],"ans":"İçten dışa ksilem, kambiyum, floem sıralanır (kollateral açık demet)."},{"q":"Dikot gövdedeki iletim demeti tipine \"açık kollateral demet\" denir. Bu demet tipinin temel özelliği nedir?","steps":[{"t":"Kollateral terimi","a":"Ksilem ve floem yan yana","d":"Kollateral demet, ksilem ve floemin aynı yarıçap üzerinde yan yana (içte ksilem, dışta floem) bulunduğu demet tipidir. Dikot gövdelerin tipik demet yapısıdır."},{"t":"Açık olması","a":"Arada kambiyum bulunur","d":"Demetin açık olması, ksilem ile floem arasında kambiyumun bulunması demektir. Bu kambiyum ikincil büyüme yeteneği sağlar."}],"ans":"Ksilem ile floem yan yana ve aralarında kambiyum bulunur; ikincil büyüme yapabilir."},{"q":"Dikot gövdede iletim demetlerinin düzenli bir halka biçiminde dizilmesi taşıma açısından hangi avantajı sağlar?","steps":[{"t":"Düzenli dizilim","a":"Demetler halka oluşturur","d":"Dikot gövdede iletim demetleri merkez çevresinde tek bir halka boyunca düzenli dizilir. Bu sayede ksilem ve floem belirli bir hatta toplanır."},{"t":"Sağladığı avantaj","a":"Kambiyum kesintisiz halka kurabilir","d":"Demetlerin halka biçiminde dizilmesi, demet kambiyumlarının demetler arası kambiyumla birleşip kesintisiz bir kambiyum halkası oluşturmasını kolaylaştırır. Bu da düzenli ikincil büyümeyi mümkün kılar."}],"ans":"Düzenli halka, kambiyumun birleşip ikincil büyümeyi düzenli yapmasını sağlar."},{"q":"Dikot gövde epidermisinin yapısını ve görevini açıklayınız. Epidermis su kaybını nasıl azaltır?","steps":[{"t":"Epidermisin yapısı","a":"Tek sıra canlı hücre","d":"Epidermis, gövdenin en dışını örten tek sıralı canlı hücre tabakasıdır. Hücreler birbirine sıkıca yapışıktır ve aralarında boşluk yoktur."},{"t":"Kütikula","a":"Üzeri kütikula ile kaplı","d":"Epidermis hücrelerinin dış yüzeyi kütin maddesinden oluşan kütikula ile kaplıdır. Kütikula su geçirmez bir tabakadır."},{"t":"Su kaybını önleme","a":"Kütikula terlemeyi azaltır","d":"Kütikula tabakası gövdeden buharlaşmayı engelleyerek su kaybını (terlemeyi) azaltır. Böylece epidermis hem koruma hem de su tutma görevi yapar."}],"ans":"Tek sıra hücreden oluşur; üzerindeki kütikula su kaybını azaltır ve gövdeyi korur."},{"q":"Dikot gövdede korteks bölgesinin yapısı ve görevleri nelerdir?","steps":[{"t":"Korteksin konumu","a":"Epidermis ile iletim demetleri arasında","d":"Korteks, epidermisin hemen altından iletim demetlerine kadar uzanan geniş bölgedir. Çoğunlukla parankima hücrelerinden oluşur."},{"t":"İçerdiği dokular","a":"Destek dokular da bulunur","d":"Korteksde parankimanın yanı sıra kollenkima ve sklerenkima gibi destek dokuları da bulunabilir. Bunlar gövdeye mekanik destek sağlar."},{"t":"Görevleri","a":"Destek ve depolama","d":"Korteks hem gövdeye destek verir hem de parankima hücrelerinde besin ve su depolar. Kloroplast içeren hücreler varsa fotosentez de yapabilir."}],"ans":"Parankima ağırlıklı geniş bölgedir; destek, depolama ve bazen fotosentez görevi yapar."},{"q":"Dikot gövdede ksilem (odun borusu) hangi maddeleri, hangi yönde taşır ve hücre özellikleri nelerdir?","steps":[{"t":"Taşıdığı madde","a":"Su ve mineral taşır","d":"Ksilem, kökten alınan su ve suda çözünmüş mineralleri taşır. Bu inorganik maddeleri yapraklara ulaştırır."},{"t":"Taşıma yönü","a":"Aşağıdan yukarıya","d":"Ksilemdeki taşıma tek yönlüdür ve kökten yapraklara, yani aşağıdan yukarıya doğru gerçekleşir. Terleme ve kök basıncı bu taşımayı sağlar."},{"t":"Hücre özelliği","a":"Ölü, kalın çeperli hücreler","d":"Ksilem; trakeit ve trake adı verilen ölü, kalın ve odunlaşmış çeperli hücrelerden oluşur. Bu yapı hem taşımayı kolaylaştırır hem de gövdeye destek verir."}],"ans":"Su ve mineralleri kökten yapraklara (yukarı) taşır; ölü, kalın çeperli hücrelerden oluşur."},{"q":"Dikot gövdede floem (soymuk borusu) hangi maddeleri, hangi yönde taşır ve hücre özellikleri nelerdir?","steps":[{"t":"Taşıdığı madde","a":"Organik besin taşır","d":"Floem, yapraklarda fotosentezle üretilen organik besinleri (özellikle sakkarozu) taşır. Bu besinler bitkinin diğer kısımlarına ulaştırılır."},{"t":"Taşıma yönü","a":"Çift yönlü taşıma","d":"Floemdeki taşıma çift yönlüdür; besin hem yukarıya büyüyen tomurcuklara hem de aşağıya köklere taşınabilir. Taşıma kaynaktan tüketim bölgesine doğrudur."},{"t":"Hücre özelliği","a":"Canlı kalburlu borular","d":"Floem; çekirdeğini kaybetmiş ancak canlı kalan kalburlu borularla, onlara yardımcı olan canlı arkadaş hücrelerden oluşur. Bu canlı hücreler aktif taşıma yapar."}],"ans":"Organik besini çift yönlü taşır; canlı kalburlu boru ve arkadaş hücrelerden oluşur."},{"q":"Dikot gövdedeki öz ve öz kollarının yapısını ve görevlerini açıklayınız.","steps":[{"t":"Özün konumu ve yapısı","a":"Merkezde parankima","d":"Öz, dikot gövdenin tam merkezinde yer alan parankima dokusudur. Bol miktarda boşluk içeren canlı hücrelerden oluşur."},{"t":"Öz kollarının yapısı","a":"Özden dışa uzanan hatlar","d":"Öz kolları, özden korteks bölgesine doğru iletim demetleri arasından ışınsal olarak uzanan parankima hatlarıdır. Özü çevre dokulara bağlar."},{"t":"Görevleri","a":"Depolama ve yatay taşıma","d":"Öz besin ve su depolar. Öz kolları ise su ve besinin gövdede merkezden çevreye yatay yönde taşınmasını sağlar."}],"ans":"Öz merkezde depolama yapar; öz kolları yatay (radyal) taşımayı sağlar."},{"q":"Dikot bitkiler ikincil büyüme yapabilirken bunu sağlayan meristematik doku hangisidir ve ne üretir?","steps":[{"t":"Sorumlu doku","a":"Kambiyum sorumludur","d":"Dikot gövdede ikincil büyümeyi (enine kalınlaşma) kambiyum adı verilen yanal meristem sağlar. Kambiyum ksilem ile floem arasında bulunur."},{"t":"Üretimi","a":"İçe ksilem, dışa floem","d":"Kambiyum hücreleri bölünerek içe doğru ikincil ksilem (odun), dışa doğru ikincil floem (soymuk) üretir. Bu üretim gövdeyi enine kalınlaştırır."}],"ans":"Kambiyum; içe ikincil ksilem, dışa ikincil floem üreterek ikincil büyümeyi sağlar."},{"q":"Dikot gövdede iletim demetinin \"açık\" olması ne anlama gelir ve bu özelliğin bitki için sonucu nedir?","steps":[{"t":"Açık demet tanımı","a":"Kambiyum içerir","d":"Bir iletim demetinin açık olması, ksilem ile floem arasında kambiyum bulundurması demektir. Dikot gövde demetleri açık tiptedir."},{"t":"Sonucu","a":"İkincil büyüme mümkün olur","d":"Demetteki kambiyum sürekli bölünebildiği için gövde her yıl kalınlaşabilir. Bu nedenle dikot bitkiler odunlaşıp ağaç ve çalı halinde büyüyebilir."}],"ans":"Demette kambiyum bulunur; bu nedenle bitki ikincil büyüme yapıp kalınlaşabilir."},{"q":"Bir ağaç gövdesindeki yıllık halkalar nasıl oluşur ve ne işe yarar?","steps":[{"t":"Mevsimsel üretim","a":"Kambiyum mevsime göre farklı üretir","d":"Kambiyum ilkbaharda hızlı büyüme nedeniyle geniş ve açık renkli ksilem hücreleri, yaz sonu ve sonbaharda yavaş büyüme nedeniyle dar ve koyu hücreler üretir."},{"t":"Halka oluşumu","a":"Açık-koyu çiftler halka yapar","d":"Bir ilkbahar (açık) ve bir sonbahar (koyu) ksilem tabakası birlikte bir yıllık halkayı oluşturur. Her halka bir yılı temsil eder."},{"t":"Yararı","a":"Ağacın yaşı belirlenir","d":"Gövde kesitindeki halkalar sayılarak ağacın yaşı hesaplanabilir. Ayrıca halka genişliği o yılın iklim koşulları hakkında bilgi verir."}],"ans":"Kambiyumun mevsimsel ksilem üretimiyle oluşur; ağacın yaşını gösterir."},{"q":"Dikot gövdede kollenkima ve sklerenkima destek dokularının görevini ve farkını açıklayınız.","steps":[{"t":"Kollenkima","a":"Canlı, esnek destek","d":"Kollenkima, köşeleri kalınlaşmış canlı hücrelerden oluşan destek dokusudur. Genellikle gövdenin genç ve büyüyen kısımlarına esnek destek sağlar."},{"t":"Sklerenkima","a":"Ölü, sert destek","d":"Sklerenkima, çeperleri ligninle kalınlaşmış ölü hücrelerden oluşur. Gövdenin olgun kısımlarına sert ve kalıcı destek verir."},{"t":"Fark","a":"Biri canlı-esnek, diğeri ölü-sert","d":"Kollenkima canlıdır ve esnek destek sağlarken, sklerenkima ölüdür ve sert destek sağlar. İkisi birlikte gövdenin dik durmasına katkıda bulunur."}],"ans":"Kollenkima canlı-esnek, sklerenkima ölü-sert destek sağlar; ikisi de gövdeyi dik tutar."},{"q":"Dikot gövdede primer (birincil) büyüme ile sekonder (ikincil) büyüme arasındaki fark nedir?","steps":[{"t":"Primer büyüme","a":"Uçtan uzama","d":"Primer büyüme, gövde ucundaki uç (apikal) meristemin bölünmesiyle gerçekleşen boyuna uzamadır. Bu sayede bitki boylanır."},{"t":"Sekonder büyüme","a":"Enine kalınlaşma","d":"Sekonder büyüme, kambiyum gibi yanal meristemlerin bölünmesiyle gerçekleşen enine kalınlaşmadır. Bu sayede gövde kalınlaşır."},{"t":"Fark","a":"Boyuna karşı enine","d":"Primer büyüme boyuna uzama (uçtan), sekonder büyüme enine kalınlaşma (yanal kambiyumdan) sağlar. Dikotlar her ikisini de yapabilir."}],"ans":"Primer büyüme uçtan boyuna uzama, sekonder büyüme kambiyumla enine kalınlaşmadır."},{"q":"Dikot gövdede kütikula tabakasının önemini ve hangi dokuyla ilişkili olduğunu açıklayınız.","steps":[{"t":"Kütikulanın yeri","a":"Epidermis üzerinde","d":"Kütikula, epidermis hücrelerinin dış yüzeyini örten kütin maddesinden oluşan bir tabakadır. Epidermisin salgıladığı bir örtüdür."},{"t":"Önemi","a":"Su kaybını önler","d":"Su geçirmez yapısı sayesinde kütikula, gövde yüzeyinden buharlaşmayı azaltır. Böylece bitkinin su kaybını (terlemeyi) sınırlar ve kuruluğa karşı korur."}],"ans":"Epidermis üzerindeki kütikula su kaybını önler ve gövdeyi dış etkilerden korur."}],"zor":[{"q":"Dikot gövdede demet kambiyumunun yanı sıra \"demetler arası kambiyum\" da oluşur. Bu iki kambiyumun birleşmesi ikincil büyümeyi nasıl etkiler?","steps":[{"t":"Demet kambiyumu","a":"Demet içinde başlangıç kambiyumu","d":"Her iletim demetinde ksilem ile floem arasında demet (intrafasiküler) kambiyumu bulunur. Bu kambiyum başlangıçta sadece demet içinde etkindir."},{"t":"Demetler arası kambiyum","a":"Öz kollarında yeni kambiyum oluşur","d":"Demetler arasındaki öz kolu parankimasında, hücreler yeniden bölünme yeteneği kazanarak demetler arası (interfasiküler) kambiyumu oluşturur. Bu kambiyum demetler arası boşlukları doldurur."},{"t":"Birleşme ve sonuç","a":"Kesintisiz kambiyum halkası","d":"İki kambiyum birleşerek gövde boyunca kesintisiz bir kambiyum halkası oluşturur. Bu halka her noktada eşit bölünerek düzenli ve dairesel bir ikincil büyüme sağlar."}],"ans":"Demet ve demetler arası kambiyum birleşip kesintisiz halka kurar; düzenli dairesel ikincil büyüme sağlar."},{"q":"Dikot gövdede ikincil büyüme ilerledikçe odunda \"öz odunu\" ve \"diri odun\" ayrımı ortaya çıkar. Bu ayrımın nedenini ve işlevsel sonucunu açıklayınız.","steps":[{"t":"Odunun yaşlanması","a":"İç odun zamanla tıkanır","d":"Yıllar geçtikçe gövdenin merkezindeki eski ksilem boruları reçine, tanen gibi maddelerle dolar ve su iletimi durur. Bu iç bölgeye öz odunu (heartwood) denir."},{"t":"Dış odun","a":"Dış halkalar aktif kalır","d":"Kambiyuma yakın dıştaki genç ksilem halkaları su taşımaya devam eder. Bu açık renkli, işlevsel bölgeye diri odun (sapwood) denir."},{"t":"İşlevsel sonuç","a":"Taşıma dışta, destek içte","d":"Su iletimi yalnızca diri odunda gerçekleşirken, öz odunu ağaca yalnızca mekanik destek sağlar. Böylece yaşlı ağaçlar içleri çürüse bile ayakta kalabilir."}],"ans":"Eski iç ksilemin tıkanmasıyla öz odunu (destek) ve işlevsel diri odun (su taşır) ayrımı oluşur."},{"q":"Dikot gövdede periderm oluşumu sırasında \"lentisel\" adı verilen yapılar gelişir. Lentiselin oluşum nedeni ve görevi nedir?","steps":[{"t":"Peridermin sorunu","a":"Periderm su geçirmez","d":"İkincil büyümeyle epidermisin yerini alan periderm, mantar hücrelerinden oluşur ve gaz geçirmez bir tabakadır. Bu durum gövde içindeki canlı hücrelerin gaz alışverişini engeller."},{"t":"Lentiselin oluşumu","a":"Mantar dokusunda gevşek bölge oluşur","d":"Mantar kambiyumu bazı bölgelerde gevşek dizilmiş, bol boşluklu hücreler üretir. Bu gevşek bölge peridermi yararak lentiseli oluşturur."},{"t":"Görevi","a":"Gaz alışverişini sağlar","d":"Lentiseller, peridermdeki bu gözenekler sayesinde gövde içindeki canlı dokuların atmosferle gaz (oksijen ve karbondioksit) alışverişi yapmasını sağlar. Yapraklardaki stoma görevini gövdede üstlenirler."}],"ans":"Su geçirmez peridermde mantar kambiyumunun açtığı gözeneklerdir; gövdede gaz alışverişini sağlar."},{"q":"Dikot iletim demetinde ksilemin merkeze yakın (içte), floemin çevreye yakın (dışta) konumlanması fonksiyonel olarak hangi avantajları sağlar?","steps":[{"t":"Ksilemin içte olması","a":"Su taşıma ve destek merkezde","d":"Ksilem kalın çeperli ölü hücrelerden oluşur. İçte (merkeze yakın) konumlanması, gövdenin merkezinde güçlü bir destek iskeleti oluşturur ve su sütununu mekanik olarak korur."},{"t":"Floemin dışta olması","a":"Besin dağıtımı çevreye yakın","d":"Floem canlı hücrelerden oluşur ve besini büyüyen bölgelere taşır. Dışta konumlanması, besinin korteks ve büyüme bölgelerine kolayca ulaşmasını sağlar."},{"t":"Kambiyumun aradaki rolü","a":"Çift yönlü üretim için ideal konum","d":"Aralarındaki kambiyum içe ksilem dışa floem üretir. Bu konumlanma, kambiyumun her iki dokuyu da doğru yöne ekleyerek gövdenin işlevsel bütünlüğünü korumasını sağlar."}],"ans":"İçteki ksilem merkezde destek ve su taşıma; dıştaki floem çevreye besin dağıtımı sağlar; kambiyum aralarında çift yönlü üretim yapar."},{"q":"Dikot gövde ile dikot kökün enine kesitleri karşılaştırıldığında iletim demeti düzenindeki temel fark nedir ve bu farkın nedeni açıklanabilir mi?","steps":[{"t":"Gövdedeki düzen","a":"Gövdede kollateral demet","d":"Dikot gövdede ksilem ve floem aynı yarıçap üzerinde yan yana (içte ksilem, dışta floem) bulunur. Bu kollateral düzen halka biçiminde tekrarlanır."},{"t":"Kökteki düzen","a":"Kökte radyal demet","d":"Dikot kökte ise ksilem ve floem aynı yarıçapta değil, dönüşümlü olarak farklı yarıçaplarda dizilir. Ksilem genellikle merkezde yıldız (X) şeklini alır, floem kollar arasına yerleşir."},{"t":"Farkın nedeni","a":"Su alımı ve taşıma yönü farkı","d":"Kökte radyal düzen, topraktan alınan suyun her yönden merkeze ulaşmasını kolaylaştırır. Gövdede ise kollateral düzen, su ve besinin organlar arası dikey taşınmasına ve ikincil büyümeye uygundur."}],"ans":"Gövdede kollateral (yan yana), kökte radyal (dönüşümlü) demet bulunur; bu fark su alımı ve taşıma işlevlerinden kaynaklanır."},{"q":"Dikot bir gövdede kambiyum içe ve dışa farklı hızlarda hücre ürettiğinde gövde kesitinde gözlenen ksilem/floem oranı nasıl şekillenir ve neden?","steps":[{"t":"Kambiyumun üretim dengesi","a":"İçe daha çok hücre üretilir","d":"Demet kambiyumu bölündüğünde içe doğru ürettiği ksilem hücrelerinin sayısı, dışa ürettiği floem hücrelerinden belirgin şekilde fazladır. Bu üretim asimetriktir."},{"t":"Floemin durumu","a":"Eski floem ezilir","d":"Dışta üretilen floem hücreleri, gövde kalınlaştıkça oluşan iç basınçla ezilir ve eskiyen floem tabakaları işlevini yitirip kabuk içinde sıkışır. Bu da floem kalınlığını sınırlar."},{"t":"Sonuç oran","a":"Ksilem baskın olur","d":"Hem içe daha fazla ksilem üretilmesi hem de eski floemin ezilmesi nedeniyle, gövde kesitinde ksilem (odun) hacim olarak floemden çok daha baskındır. Bu yüzden ağaç gövdesinin büyük kısmı odundur."}],"ans":"Kambiyum içe daha çok ksilem üretir ve eski floem ezilir; bu nedenle ksilem (odun) floemden çok daha fazla yer kaplar."},{"q":"Dikot gövdede su, terleme-kohezyon-gerilim teorisine göre ksilemde nasıl yukarı taşınır? Bu süreçte ksilem hücre yapısının rolü nedir?","steps":[{"t":"Terleme ile çekim","a":"Yapraktan su buharlaşır","d":"Yapraklardaki stomalardan su buharlaşınca (terleme), yaprak hücrelerinde bir su açığı ve çekim kuvveti (gerilim) oluşur. Bu çekim ksilemdeki su sütununu yukarı doğru çeker."},{"t":"Kohezyon ve adezyon","a":"Su molekülleri birbirine tutunur","d":"Su molekülleri hidrojen bağlarıyla birbirine tutunur (kohezyon) ve ksilem çeperine yapışır (adezyon). Bu sayede su sütunu kopmadan kesintisiz biçimde yukarı taşınır."},{"t":"Ksilem yapısının rolü","a":"Ölü, dar ve sürekli borular","d":"Ksilem ölü, içi boş ve uçları açık dar borulardan oluşur; bu yapı su sütununun sürtünmesini azaltır ve kesintisiz bir sütun oluşmasını sağlar. Kalın çeperleri gerilim altında çökmeyi önler."}],"ans":"Terlemeyle oluşan çekim, suyun kohezyon-adezyonuyla ksilemde kesintisiz sütun halinde yukarı taşınır; ksilemin ölü, dar, açık boruları bunu mümkün kılar."},{"q":"Dikot gövdede floemde besin taşınması \"basınç akış (kütle akış) hipotezi\" ile açıklanır. Bu mekanizmada kaynak ve havuz bölgeleri ne rol oynar?","steps":[{"t":"Kaynak bölgesi","a":"Besin floeme yüklenir","d":"Fotosentezin yapıldığı yaprak gibi kaynak bölgelerde sakkaroz aktif taşımayla floeme yüklenir. Bu yükleme floem hücrelerinin ozmotik basıncını artırır ve içeri su girer."},{"t":"Havuz bölgesi","a":"Besin floemden boşaltılır","d":"Kök ve meyve gibi havuz (tüketim) bölgelerinde sakkaroz floemden boşaltılır. Bu boşalma havuz ucundaki ozmotik basıncı düşürür ve buradan su çıkar."},{"t":"Basınç farkı ile akış","a":"Yüksek basınçtan düşüğe akar","d":"Kaynaktaki yüksek basınç ile havuzdaki düşük basınç arasında oluşan fark, floem özsuyunu kaynaktan havuza doğru kütlesel olarak iter. Böylece besin çift yönlü taşınabilir."}],"ans":"Kaynakta yüklenen sakkaroz basınç artırır, havuzda boşalma basınç düşürür; oluşan basınç farkı floem özsuyunu kaynaktan havuza iter."},{"q":"Dikot gövdede arkadaş hücrelerin (refakatçi hücre) kalburlu borularla olan ilişkisi ve floem taşınmasındaki işlevsel önemi nedir?","steps":[{"t":"Kalburlu borunun eksiği","a":"Çekirdeğini kaybetmiştir","d":"Floemdeki kalburlu boru hücreleri olgunlaşırken çekirdeklerini ve birçok organelini kaybeder. Bu nedenle kendi metabolik faaliyetlerini tek başlarına yürütemezler."},{"t":"Arkadaş hücrenin rolü","a":"Çekirdekli, metabolik destek verir","d":"Her kalburlu boruya bir veya daha fazla çekirdekli, organelce zengin arkadaş hücre eşlik eder. Plazmodesmalarla bağlı bu hücreler kalburlu borunun yaşamsal işlevlerini yönetir."},{"t":"Taşımadaki önemi","a":"Aktif yükleme sağlar","d":"Arkadaş hücreler ATP harcayarak sakkarozu floeme aktif olarak yükler ve boşaltır. Böylece floemdeki besin taşınması için gereken enerjiyi ve basınç farkını sağlar."}],"ans":"Çekirdeğini kaybeden kalburlu borunun yaşamını yönetir ve sakkarozun aktif yüklenmesini sağlayarak floem taşınmasını mümkün kılar."},{"q":"Dikot gövdede kabuk halka çıkarıldığında (kuşaklama/halkalama) ağacın zamanla ölmesinin nedeni iletim dokuları açısından nasıl açıklanır?","steps":[{"t":"Kabukta hangi doku var","a":"Kabukta floem bulunur","d":"Bir ağacın kabuğu kambiyumun dışındaki floemi ve peridermi içerir. Kambiyumdan dışa doğru olan tüm dokular kabuk halkasıyla birlikte çıkar."},{"t":"Halkalama sonucu","a":"Floem yolu kesilir","d":"Gövde çevresinde bir halka kabuk çıkarıldığında floem dokusu o noktada kesintiye uğrar. Yapraklarda üretilen besin artık köklere taşınamaz."},{"t":"Ağacın ölümü","a":"Kökler aç kalır","d":"Besin köklere ulaşamayınca kökler enerji bulamaz ve zamanla ölür. Kökler ölünce su alımı duracağı için ağacın tamamı ölür. Ksilem içte sağlam kaldığından bir süre su taşımaya devam etse de besinsizlik ölümcüldür."}],"ans":"Halkalama floemi keser, yapraklardaki besin köklere ulaşamaz; aç kalan kökler ölünce su alımı durur ve ağaç ölür."},{"q":"Dikot gövdede sklerenkima hücrelerinin lignin içermesi mekanik destek dışında bitki için hangi ek avantajları sağlar?","steps":[{"t":"Ligninin yapısı","a":"Sert, dayanıklı polimer","d":"Lignin, sklerenkima ve odunlaşmış ksilem çeperlerinde biriken sert ve dayanıklı bir polimerdir. Hücre çeperini sertleştirir ve su geçirmez hale getirir."},{"t":"Mekanik avantaj","a":"Gövdeyi dik tutar","d":"Ligninle güçlenmiş sklerenkima, gövdeye yüksek mekanik dayanıklılık kazandırır. Bu sayede bitki rüzgar ve kendi ağırlığına karşı dik durabilir."},{"t":"Ek avantajlar","a":"Patojen ve su kaybına direnç","d":"Lignin su geçirmez olduğu için ksilemde su iletimini desteklerken kayıpları azaltır. Ayrıca sertliği ve kimyasal yapısı, mantar ve bakteri gibi patojenlerin dokuya girmesini zorlaştırarak bitkiyi hastalıklara karşı korur."}],"ans":"Mekanik destek dışında su geçirmezlik (ksilemde iletim) ve patojenlere karşı dirence katkı sağlar."},{"q":"Dikot gövdede uç meristem ile yanal meristem (kambiyum) arasında zamansal ve mekansal iş bölümü nasıldır? İkisi birlikte gövdeyi nasıl şekillendirir?","steps":[{"t":"Uç meristem","a":"Önce boyuna uzatır","d":"Gövde ucundaki apikal (uç) meristem önce etkinleşir ve hücre bölünmesiyle gövdeyi boyuna uzatarak primer dokuları oluşturur. Bu primer büyümedir."},{"t":"Yanal meristem","a":"Sonra enine kalınlaştırır","d":"Primer büyüme tamamlanan bölgelerde, yanal meristem olan kambiyum etkinleşir. Kambiyum enine bölünerek gövdeyi kalınlaştırır; bu sekonder büyümedir."},{"t":"Birlikte şekillendirme","a":"Boyca uzar, enine kalınlaşır","d":"Uç meristem gövdeyi yukarı doğru uzatırken, alttaki olgun bölgelerde kambiyum gövdeyi kalınlaştırır. İki meristemin uyumlu çalışması ağacın hem boylanıp hem de gövde tabanına doğru kalınlaşmasını sağlar."}],"ans":"Uç meristem önce boyuna uzatır (primer), ardından kambiyum olgun bölgeleri enine kalınlaştırır (sekonder); birlikte ağacı hem boylandırır hem kalınlaştırır."},{"q":"Dikot gövdede ikincil büyüme sürecinde \"vasküler kambiyum\" ve \"mantar kambiyumu\" olmak üzere iki yanal meristem görev alır. Bu iki kambiyumun ürettiği dokuları ve konumlarını karşılaştırınız.","steps":[{"t":"Vasküler kambiyum","a":"İletim dokularını üretir","d":"Vasküler (demet) kambiyum ksilem ile floem arasında bulunur. İçe doğru ikincil ksilem (odun), dışa doğru ikincil floem üreterek iletim sistemini kalınlaştırır."},{"t":"Mantar kambiyumu","a":"Koruyucu dokuyu üretir","d":"Mantar kambiyumu (fellojen) korteks bölgesinde, daha dışta yer alır. Dışa doğru mantar (fellem), içe doğru fellodermi üreterek koruyucu peridermi oluşturur."},{"t":"Karşılaştırma","a":"Biri iletim, diğeri koruma","d":"Vasküler kambiyum iç bölgede iletim dokularını çoğaltırken, mantar kambiyumu dış bölgede koruyucu örtüyü üretir. İkisi birlikte gövdenin hem iletimini hem korunmasını sekonder büyümeyle sürdürür."}],"ans":"Vasküler kambiyum içe ksilem-dışa floem (iletim) üretir; mantar kambiyumu daha dışta dışa mantar-içe felloderm (koruyucu periderm) üretir."},{"q":"Dikot gövdede otsu (zayıf ikincil büyüme) ile odunsu yapı arasındaki fark, kambiyum etkinliği temelinde nasıl açıklanır?","steps":[{"t":"Otsu dikotlar","a":"Kambiyum az çalışır","d":"Otsu dikot bitkilerde kambiyum ya çok az etkindir ya da kısa süre çalışır. Bu nedenle gövdede çok az ikincil ksilem birikir ve gövde yumuşak, esnek kalır."},{"t":"Odunsu dikotlar","a":"Kambiyum sürekli çalışır","d":"Odunsu dikotlarda (ağaç ve çalılar) kambiyum yıllarca etkin kalır ve sürekli ikincil ksilem üretir. Biriken odun gövdeyi sert ve kalın yapar."},{"t":"Sonuç","a":"Kambiyum süresi yapıyı belirler","d":"Gövdenin otsu mu yoksa odunsu mu olacağı, kambiyumun ne kadar süre ve hangi yoğunlukta çalıştığına bağlıdır. Uzun süreli yoğun kambiyum etkinliği odunlaşmaya, sınırlı etkinlik otsu yapıya yol açar."}],"ans":"Kambiyum az/kısa süre çalışırsa otsu yumuşak gövde, uzun süre yoğun çalışırsa odun biriken odunsu gövde oluşur."},{"q":"Dikot gövdede iletim demetlerinin halka düzeninde dizilmesi ve aralarında öz kollarının bulunması, ikincil büyüme başladığında kambiyum halkasının oluşumunu nasıl kolaylaştırır?","steps":[{"t":"Başlangıç durumu","a":"Demetler halka, aralarda öz kolları","d":"Dikot gövdede iletim demetleri merkez çevresinde düzenli bir halka oluşturur ve demetler arasındaki boşluklar öz kolu parankimasıyla doludur. Her demette demet kambiyumu vardır."},{"t":"Demetler arası kambiyum","a":"Öz kolları kambiyuma dönüşür","d":"İkincil büyüme başlayınca öz kollarındaki parankima hücreleri yeniden bölünme yeteneği kazanır ve demetler arası kambiyumu oluşturur. Bu kambiyum, komşu demetlerin demet kambiyumlarını birbirine bağlar."},{"t":"Kesintisiz halka","a":"Tam bir kambiyum çemberi","d":"Demet kambiyumları ile demetler arası kambiyumun birleşmesi sonucu gövde boyunca kesintisiz tam bir kambiyum halkası oluşur. Demetlerin düzenli halka dizilimi ve öz kollarının aradaki konumu bu birleşmeyi geometrik olarak kolaylaştırır."}],"ans":"Düzenli demet halkası ve aradaki öz kolları, demet kambiyumları ile öz kollarından oluşan demetler arası kambiyumun birleşip kesintisiz bir kambiyum halkası kurmasını kolaylaştırır."}]}},"govdeMonokot":{"ilkokul":{"kolay":[{"q":"Tek çenekli bir bitkinin (örneğin mısır veya buğday) gövdesini enine kestiğimizde, su taşıyan boru demetlerinin gövdeye nasıl dağıldığını görürüz?","steps":[{"t":"Boruların yerine bakalım","a":"Borular her yere dağılmış","d":"Tek çenekli bir gövdeyi enine kestiğimizde su taşıyan boru demetleri belli bir düzen göstermez. Gövdenin her yerine yayılmış gibi görünürler."},{"t":"Dağınık görünüm","a":"Düzensiz dağılım var","d":"Bu demetler gövde içinde dağınık ve düzensiz biçimde yer alır. Bu dağınık görünüm tek çenekli bitki gövdelerinin önemli bir özelliğidir."}],"ans":"Boru demetleri gövdeye dağınık (düzensiz) biçimde yayılmıştır."},{"q":"Buğday, mısır ve çimen gibi tek çenekli bitkilerin gövdeleri genellikle çok kalınlaşır mı yoksa ince mi kalır?","steps":[{"t":"Bu bitkilere bakalım","a":"Gövdeleri incedir","d":"Buğday, mısır ve çimen gibi bitkilerin gövdeleri genellikle ince ve uzundur. Ağaç gibi yıllar içinde kalın bir gövde oluşturmazlar."},{"t":"Neden ince kalır","a":"Enine kalınlaşma yapamazlar","d":"Tek çenekli bu bitkiler gövdelerini her yıl kalınlaştıramaz. Bu yüzden gövdeleri yaşamları boyunca genellikle ince kalır."}],"ans":"Genellikle ince kalır, çok kalınlaşmazlar."},{"q":"Tek çenekli bir bitkinin gövdesinin görevlerinden biri nedir? Mısır bitkisinde gövde ne işe yarar?","steps":[{"t":"Gövdenin işi","a":"Gövde bitkiyi dik tutar","d":"Mısır gibi tek çenekli bir bitkide gövde, bitkiyi toprak üzerinde dik tutar. Yaprakların güneşe ulaşmasını sağlar."},{"t":"Taşıma görevi","a":"Su ve besini taşır","d":"Gövde aynı zamanda kökten gelen suyu yapraklara, yapraklardan gelen besini diğer kısımlara taşır. Böylece bitki beslenir ve büyür."}],"ans":"Bitkiyi dik tutar ve su ile besini taşır."},{"q":"Tek çenekli bir bitki gövdesini enine kestiğimizde tam ortada büyük bir yumuşak bölge olabilir mi? Bu bölge ne işe yarar?","steps":[{"t":"Gövdenin ortası","a":"Ortada yumuşak bir bölge var","d":"Pek çok tek çenekli bitkinin gövdesini enine kestiğimizde ortada yumuşak ve dolgun bir bölge görürüz. Bu bölge gövdenin büyük kısmını kaplayabilir."},{"t":"Bu bölgenin görevi","a":"Burada besin depolanır","d":"Bu yumuşak bölge bitkiye destek olur ve içinde besin ile su depolanabilir. Örneğin mısır gövdesinde bu bölge tatlı su biriktirebilir."}],"ans":"Ortadaki yumuşak bölge destek sağlar ve besin depolar."},{"q":"Çift çenekli bir ağaç gövdesinde taşıma boruları düzenli halka yaparken, tek çenekli bir bitki gövdesinde borular nasıl bir düzen gösterir?","steps":[{"t":"İki bitkiyi karşılaştıralım","a":"Birinde düzenli, birinde dağınık","d":"Çift çenekli ağaç gövdesinde taşıma boruları düzenli bir halka oluşturur. Tek çenekli bitki gövdesinde ise durum farklıdır."},{"t":"Tek çeneklideki düzen","a":"Borular dağınıktır","d":"Tek çenekli bitki gövdesinde taşıma boruları düzenli halka yapmaz, gövdeye dağınık biçimde yayılır. Bu, iki bitki grubu arasındaki önemli bir farktır."}],"ans":"Tek çenekli bitkide boruları dağınık dizilir, halka yapmaz."}],"zor":[{"q":"Mısır gövdesi yıllar içinde bir meşe ağacı gibi kalınlaşıp dev bir gövdeye dönüşemez. Tek çenekli bir bitkinin gövdesinin kalınlaşamamasının nedeni nedir?","steps":[{"t":"Gözlem","a":"Mısır gövdesi kalınlaşmaz","d":"Mısır gibi tek çenekli bir bitki büyüyüp uzasa da gövdesi bir ağaç gibi her yıl kalınlaşmaz. Gövdesi ince kalır."},{"t":"Eksik yapı","a":"Kalınlaştıran tabaka yok","d":"Tek çenekli bitki gövdesinde, her yıl yeni hücre tabakaları ekleyip gövdeyi kalınlaştıran özel bir bölünme tabakası bulunmaz. Bu tabaka olmadığı için gövde enine kalınlaşamaz."}],"ans":"Gövdeyi her yıl kalınlaştıran bölünme tabakası (kambiyum) bulunmadığı için kalınlaşamaz."},{"q":"Tek çenekli bir bitki gövdesinde taşıma boruları dağınık olmasına rağmen su yapraklara nasıl ulaşır?","steps":[{"t":"Boruların görevi","a":"Her boru su taşır","d":"Tek çenekli gövdede dağınık duran boru demetlerinin her biri içinde su taşıyan borular bulunur. Konumları dağınık olsa da görevleri aynıdır."},{"t":"Suyun yolculuğu","a":"Su yukarı taşınır","d":"Kökten alınan su, gövdenin her yerine dağılmış bu borular boyunca yukarıya, yapraklara taşınır. Boruların dağınık olması suyun ulaşmasını engellemez."}],"ans":"Dağınık boru demetlerinin her biri suyu yukarı taşıdığı için su yapraklara ulaşır."},{"q":"Çimen ve buğday gibi tek çenekli bitkiler ince gövdelerine rağmen rüzgarda nasıl dik kalabilir ve kolayca kırılmaz?","steps":[{"t":"Gözlem","a":"İnce gövde dik kalır","d":"Buğday ve çimen ince gövdelidir ama rüzgarda eğilip tekrar doğrulur, kolay kırılmaz. Bu esnek ve dayanıklı bir yapıya işaret eder."},{"t":"Nedeni","a":"Gövde içinde destek var","d":"Tek çenekli bitkilerin gövdesinde, özellikle dış kısımda sert destek dokuları bulunur. Bu dokular gövdeye hem esneklik hem dayanıklılık vererek dik durmasını sağlar."}],"ans":"Gövdedeki sert destek dokuları sayesinde esnek ve dayanıklıdırlar, dik kalırlar."},{"q":"Bir öğrenci mısır gövdesinin ve bir ağaç dalının enine kesitlerini karşılaştırıyor. Hangisinin tek çenekli, hangisinin çift çenekli olduğunu boruların dizilişine bakarak nasıl ayırt edebilir?","steps":[{"t":"Kesitlere bakalım","a":"İki farklı görünüm var","d":"İki kesitten birinde taşıma boruları gövdeye dağınık yayılmış, diğerinde düzenli bir halka oluşturmuştur. Bu görünüm farkı önemli bir ipucudur."},{"t":"Ayırt etme","a":"Dağınık olan tek çenekli","d":"Boruları dağınık olan kesit tek çenekli bitkiye (mısır), boruları düzenli halka yapan kesit ise çift çenekli bitkiye (ağaç dalı) aittir. Böylece dizilişe bakarak ayırt edilir."}],"ans":"Boruları dağınık olan tek çenekli (mısır), düzenli halka yapan çift çenekli (ağaç) bitkidir."},{"q":"Tek çenekli bir bitki gövdesinin dış yüzeyinde de koruyucu bir örtü vardır. Bu örtünün görevi nedir ve neden önemlidir?","steps":[{"t":"Dış örtü","a":"En dışta koruyucu tabaka var","d":"Tek çenekli bitki gövdesinin en dışında ince bir koruyucu örtü tabakası bulunur. Bu tabaka gövdenin iç kısımlarını sarar."},{"t":"Görevi","a":"Korur ve su kaybını önler","d":"Bu örtü gövdeyi dış etkilerden ve zararlılardan korur. Ayrıca gövdeden su kaybını azaltarak bitkinin kurumasını önler. Bu yüzden bitki için çok önemlidir."}],"ans":"Dış örtü gövdeyi korur ve su kaybını önler; bitkinin sağlıklı kalmasını sağlar."}]},"ortaokul":{"kolay":[{"q":"Tek çenekli (monokot) bir bitki gövdesinin enine kesitinde iletim demetleri nasıl dağılmıştır?","steps":[{"t":"Demetlere bakalım","a":"Demetler düzensizdir","d":"Monokot gövdeyi enine kestiğimizde iletim demetlerinin belirli bir düzen göstermediğini görürüz. Dikotlardaki gibi tek bir halka oluşturmazlar."},{"t":"Dağılım şekli","a":"Gövdeye dağınık yayılır","d":"İletim demetleri gövdenin her tarafına dağınık (düzensiz) biçimde yayılır. Bu dağınık dağılım monokot gövdelerin temel özelliğidir."}],"ans":"İletim demetleri gövdeye dağınık (düzensiz) biçimde dağılmıştır."},{"q":"Monokot bir bitki gövdesinde iletim demetinin içinde kambiyum bulunur mu? Bu durumun adı nedir?","steps":[{"t":"Demetin içi","a":"Kambiyum yoktur","d":"Monokot iletim demetinde ksilem ile floem arasında kambiyum tabakası bulunmaz. Bu nedenle demet bölünüp gelişemez."},{"t":"Demet tipinin adı","a":"Kapalı demet denir","d":"Kambiyum içermeyen bu demet tipine kapalı demet denir. Monokot gövdedeki iletim demetleri kapalı tiptedir."}],"ans":"Kambiyum bulunmaz; bu demet tipine kapalı demet denir."},{"q":"Monokot bitkiler genellikle ikincil büyüme (enine kalınlaşma) yapabilir mi? Nedenini açıklayınız.","steps":[{"t":"İkincil büyüme","a":"Genellikle yapamazlar","d":"Monokot bitkiler çoğunlukla gövdelerini enine kalınlaştıramaz, yani ikincil büyüme yapamaz. Gövdeleri genellikle ince kalır."},{"t":"Nedeni","a":"Kambiyum bulunmaz","d":"İkincil büyümeyi sağlayan kambiyum monokot demetlerinde bulunmadığı için gövde kalınlaşamaz. Bu yüzden monokot bitkiler genellikle odunlaşmaz."}],"ans":"Genellikle yapamazlar çünkü kambiyumları bulunmaz."},{"q":"Dikot gövde ile monokot gövde arasında iletim demetlerinin dizilişi bakımından temel fark nedir?","steps":[{"t":"Dikot gövde","a":"Demetler halka şeklinde","d":"Dikot gövdede iletim demetleri merkez çevresinde düzenli bir halka oluşturacak biçimde dizilir. Bu düzenli dizilim dikotlara özgüdür."},{"t":"Monokot gövde","a":"Demetler dağınık","d":"Monokot gövdede ise iletim demetleri halka yapmaz, gövdeye dağınık olarak yayılır. İşte iki grup arasındaki temel fark budur."}],"ans":"Dikotta demetler düzenli halka yapar, monokotta dağınık dağılır."},{"q":"Monokot gövdede de su ve mineraller bir doku ile taşınır. Su ve mineralleri taşıyan bu dokunun adı nedir?","steps":[{"t":"Taşınan madde","a":"Su ve mineral taşınır","d":"Monokot gövdede de kökten alınan su ve mineraller yapraklara taşınır. Bu taşıma için demetlerin içinde özel bir doku bulunur."},{"t":"Dokunun adı","a":"Bu doku ksilemdir","d":"Su ve mineralleri taşıyan bu dokuya ksilem (odun borusu) denir. Ksilem hem dikot hem monokot gövdede su taşıma görevini yapar."}],"ans":"Ksilem (odun borusu)"}],"zor":[{"q":"Monokot bir iletim demetinde kambiyum bulunmamasının (kapalı demet) bitkinin büyümesi üzerindeki sonucu nedir?","steps":[{"t":"Kambiyumun olmaması","a":"Demet bölünemez","d":"Monokot demetinde ksilem ile floem arasında kambiyum yoktur. Bu nedenle demet, yeni ksilem ve floem üreterek gelişemez."},{"t":"Büyümeye etkisi","a":"Enine kalınlaşma olmaz","d":"Kambiyum olmadığı için gövde ikincil büyüme yapamaz ve enine kalınlaşamaz. Demet bir kez oluştuktan sonra kalınlığı genellikle sabit kalır."},{"t":"Sonuç","a":"İnce gövde, çoğunlukla otsu","d":"Bu yüzden monokot bitkiler genellikle ince gövdeli ve otsu yapıda kalır, ağaç gibi kalın odun oluşturamaz."}],"ans":"Kambiyum olmadığından gövde enine kalınlaşamaz; bitki ince ve genellikle otsu kalır."},{"q":"Bir öğrenci mikroskop altında bir gövde kesitinde iletim demetlerinin dağınık olduğunu ve demetlerde kambiyum olmadığını gözlemliyor. Bu gövde dikot mu yoksa monokot mu aittir? Gerekçesini açıklayınız.","steps":[{"t":"Demet dizilişi","a":"Dağınık dizilim gözlenmiş","d":"Gözlemde iletim demetleri düzenli halka değil, dağınık biçimde dağılmış. Dağınık demet dizilişi monokot gövdelerin özelliğidir."},{"t":"Kambiyum durumu","a":"Kambiyum yok (kapalı demet)","d":"Demetlerde kambiyum bulunmaması, demetlerin kapalı tipte olduğunu gösterir. Kapalı demet de monokotlara özgüdür."},{"t":"Sonuç","a":"Gövde monokottur","d":"Hem dağınık demet dizilişi hem de kambiyum yokluğu birlikte değerlendirildiğinde bu gövdenin monokot (tek çenekli) bir bitkiye ait olduğu anlaşılır."}],"ans":"Monokot gövdedir; çünkü demetler dağınık ve kambiyumsuz (kapalı) tiptedir."},{"q":"Monokot gövdede iletim demetleri dağınık olduğu için dikottaki gibi belirgin bir öz, korteks ve öz kolu ayrımı görülür mü? Açıklayınız.","steps":[{"t":"Dikottaki ayrım","a":"Dikotta net bölgeler var","d":"Dikot gövdede demetler halka yaptığı için içte öz, dışta korteks ve aralarda öz kolları net biçimde ayırt edilir. Bölgeler bellidir."},{"t":"Monokottaki durum","a":"Demetler her yere yayılmış","d":"Monokot gövdede demetler tüm gövdeye dağınık yayıldığı için içte öz, dışta korteks şeklinde keskin bir ayrım oluşmaz. Demetler arasındaki bölge tek tip temel parankima dokuyla doludur."},{"t":"Sonuç","a":"Belirgin ayrım yoktur","d":"Bu nedenle monokot gövdede dikottaki gibi belirgin öz, korteks ve öz kolu ayrımı görülmez. Gövde daha çok tek tip temel doku içinde gömülü demetlerden oluşur."}],"ans":"Hayır; demetler dağınık olduğu için belirgin öz, korteks ve öz kolu ayrımı görülmez, gövde tek tip temel doku içerir."},{"q":"Bambu ve hindistan cevizi ağacı gibi bazı monokot bitkiler oldukça uzun ve sağlam gövdelere sahiptir. Kambiyumları olmadığı halde bu sağlamlığı nasıl sağlarlar?","steps":[{"t":"Sorun","a":"Kambiyumsuz ama sağlam","d":"Bambu gibi bitkiler kambiyuma sahip olmadıkları için klasik anlamda odun yapamaz. Buna rağmen gövdeleri çok uzun ve sağlam olabilir."},{"t":"Destek dokuları","a":"Sklerenkima bolca bulunur","d":"Bu bitkilerin gövdelerinde, özellikle iletim demetlerinin çevresinde bol miktarda sklerenkima destek dokusu bulunur. Bu sert dokular gövdeye dayanıklılık katar."},{"t":"Sonuç","a":"Destek dokular sağlamlık sağlar","d":"Kambiyum yerine bolca biriken sklerenkima ve sıkı demet düzeni sayesinde bu monokotlar uzun ve sağlam gövdeler oluşturabilir. Yani sağlamlık ikincil büyümeden değil, destek dokularından gelir."}],"ans":"Kambiyum yerine gövdelerinde bolca bulunan sklerenkima destek dokuları sağlamlık sağlar."},{"q":"Monokot ve dikot gövdeler arasındaki demet dizilişi farkı, bu bitkilerin büyüme biçimini (boyuna ve enine) nasıl etkiler?","steps":[{"t":"Dikotun büyümesi","a":"Hem boyuna hem enine","d":"Dikot gövdede demetler halka yapar ve kambiyum içerir. Bu sayede dikotlar hem uçtan boyuna uzar hem de kambiyumla enine kalınlaşabilir."},{"t":"Monokotun büyümesi","a":"Genellikle yalnız boyuna","d":"Monokot gövdede demetler dağınık ve kambiyumsuzdur. Bu yüzden monokotlar genellikle yalnızca boyuna uzar, belirgin bir enine kalınlaşma yapamaz."},{"t":"Sonuç","a":"Yapı büyümeyi belirler","d":"Demet dizilişi ve kambiyum varlığı, dikotların hem boylanıp hem kalınlaşan ağaçsı yapılar; monokotların ise çoğunlukla ince ve otsu yapılar oluşturmasını belirler."}],"ans":"Dikot kambiyumuyla boyuna ve enine büyürken, monokot kambiyumsuz olduğu için genellikle yalnız boyuna büyür."}]},"lise":{"kolay":[{"q":"Monokot (tek çenekli) bir bitki gövdesinin enine kesitindeki temel yapısal özellikleri sıralayınız.","steps":[{"t":"Demet dizilişi","a":"Dağınık demetler","d":"Monokot gövdede iletim demetleri düzenli halka yapmaz, temel doku içine dağınık biçimde gömülüdür. Bu dağınık dağılım en belirgin özelliktir."},{"t":"Demet tipi","a":"Kapalı kollateral demet","d":"Demetlerde ksilem içte, floem dışta yer alır ancak aralarında kambiyum bulunmaz. Bu nedenle demetler kapalı kollateral tiptedir."},{"t":"İkincil büyüme","a":"Genellikle yoktur","d":"Kambiyum bulunmadığı için monokot gövde genellikle ikincil büyüme yapamaz ve enine kalınlaşmaz. Gövde çoğunlukla otsu kalır."}],"ans":"Dağınık iletim demetleri, kambiyumsuz (kapalı) demetler ve genellikle ikincil büyümenin olmaması."},{"q":"Monokot gövdede iletim demetlerinin \"kapalı kollateral demet\" olarak adlandırılmasının nedeni nedir?","steps":[{"t":"Kollateral terimi","a":"Ksilem ve floem yan yana","d":"Kollateral demet, ksilem ile floemin aynı yarıçap üzerinde yan yana (içte ksilem, dışta floem) bulunduğu demet tipidir. Monokot demetleri de kollateraldir."},{"t":"Kapalı terimi","a":"Kambiyum yoktur","d":"Demetin kapalı olması, ksilem ile floem arasında kambiyum bulunmaması demektir. Monokot demetlerinde kambiyum olmadığı için demetler kapalıdır."}],"ans":"Ksilem-floem yan yana (kollateral) olup aralarında kambiyum bulunmadığı (kapalı) için bu adı alır."},{"q":"Monokot gövdede dikottaki gibi belirgin korteks, öz ve öz kolları ayrımının görülmemesinin nedeni nedir?","steps":[{"t":"Demetlerin dağılımı","a":"Demetler tüm gövdeye yayılmış","d":"Monokot gövdede iletim demetleri tek bir halka değil, gövdenin her yerine dağınık yerleşir. Demetler temel parankima dokusu içine gömülüdür."},{"t":"Bölgesel ayrımın kaybolması","a":"Tek tip temel doku","d":"Demetler her yere yayıldığı için iç-dış bölgeleme bozulur; korteks, öz ve öz kolları gibi ayrı bölgeler belirginleşmez. Demetler arası alan tek tip temel dokudan oluşur."}],"ans":"Demetler tüm gövdeye dağınık yayıldığı için belirgin korteks, öz ve öz kolu ayrımı oluşmaz."},{"q":"Monokot gövde ile dikot gövde, iletim demeti dizilişi ve kambiyum varlığı bakımından nasıl karşılaştırılır?","steps":[{"t":"Demet dizilişi","a":"Dikot halka, monokot dağınık","d":"Dikot gövdede demetler merkez çevresinde düzenli halka yapar. Monokot gövdede ise demetler dağınık olarak gövdeye yayılır."},{"t":"Kambiyum varlığı","a":"Dikotta var, monokotta yok","d":"Dikot demetlerinde ksilem ile floem arasında kambiyum (açık demet) bulunur. Monokot demetlerinde kambiyum yoktur (kapalı demet)."},{"t":"Büyüme sonucu","a":"Dikot kalınlaşır, monokot kalınlaşmaz","d":"Kambiyum sayesinde dikot ikincil büyüme yapıp kalınlaşırken, monokot genellikle ikincil büyüme yapamaz ve ince kalır."}],"ans":"Dikotta demetler halka ve kambiyumlu (açık, kalınlaşır); monokotta demetler dağınık ve kambiyumsuz (kapalı, kalınlaşmaz)."},{"q":"Monokot iletim demetinde ksilem ve floemin konumu nasıldır?","steps":[{"t":"Ksilemin konumu","a":"Ksilem içte","d":"Monokot demetinde ksilem gövde merkezine doğru, yani içte yer alır. Genellikle birkaç geniş ksilem borusu V veya Y biçiminde dizilir."},{"t":"Floemin konumu","a":"Floem dışta","d":"Floem demetin dış kısmında, gövde yüzeyine yakın konumlanır. Ksilem ile floem yan yana (kollateral) bulunur ama aralarında kambiyum yoktur."}],"ans":"Ksilem içte, floem dışta bulunur (kollateral düzen), aralarında kambiyum yoktur."},{"q":"Monokot gövdede iletim demetlerinin etrafında genellikle hangi destek doku bulunur ve görevi nedir?","steps":[{"t":"Demet çevresi","a":"Demetleri saran kılıf var","d":"Monokot gövdede her iletim demetinin çevresi genellikle bir destek doku kılıfıyla sarılıdır. Bu kılıf demeti çevreler ve korur."},{"t":"Dokunun türü ve görevi","a":"Sklerenkima destek verir","d":"Bu kılıf sıklıkla ölü, kalın çeperli sklerenkima hücrelerinden oluşur. Sklerenkima kılıfı demete ve gövdeye mekanik destek sağlayarak ince gövdenin dik kalmasına yardımcı olur."}],"ans":"Demetleri saran sklerenkima kılıfı bulunur; gövdeye mekanik destek sağlar."},{"q":"Monokot bitkiler genellikle odunlaşıp ağaç oluşturamazken otsu yapıda kalmasının iletim dokusuyla ilişkisini açıklayınız.","steps":[{"t":"Odunun kaynağı","a":"Odun ikincil ksilemdir","d":"Bir bitkinin odunlaşması, kambiyumun ürettiği ikincil ksilemin (odun) gövdede birikmesiyle olur. Odun gövdeye sertlik ve kalınlık kazandırır."},{"t":"Monokottaki eksiklik","a":"Kambiyum yok, ikincil ksilem üretilmez","d":"Monokot demetleri kapalı olduğu ve kambiyum içermediği için ikincil ksilem üretilemez. Bu nedenle gövdede odun birikmez."},{"t":"Sonuç","a":"Otsu yapı","d":"Odun birikmediği için monokot gövde kalınlaşıp sertleşemez ve çoğunlukla otsu, yumuşak yapıda kalır. Bu yüzden tipik monokotlar ağaç oluşturamaz."}],"ans":"Kambiyumsuz oldukları için ikincil ksilem (odun) üretemezler; bu nedenle odunlaşamayıp otsu kalırlar."},{"q":"Bir gövde kesitinde dağınık demet dizilişi ve kapalı demet yapısı gözlemleniyor. Bu özellikler bitkinin hangi gruba ait olduğunu nasıl ortaya koyar?","steps":[{"t":"Dağınık dizilim","a":"Monokot işareti","d":"İletim demetlerinin halka değil dağınık biçimde dizilmesi monokot gövdelerin tipik özelliğidir. Bu ilk önemli ipucudur."},{"t":"Kapalı demet","a":"Monokot işareti","d":"Demetlerde kambiyum bulunmaması, yani kapalı demet yapısı da monokotlara özgüdür. Bu da ikinci ipucudur."},{"t":"Sonuç","a":"Bitki monokottur","d":"Hem dağınık dizilim hem de kapalı demet birlikte değerlendirildiğinde, bu gövdenin tek çenekli (monokot) bir bitkiye ait olduğu kesinleşir."}],"ans":"Dağınık demet dizilişi ve kapalı demet yapısı birlikte bitkinin monokot (tek çenekli) olduğunu gösterir."},{"q":"Monokot gövdede ksilem (odun borusu) hangi maddeleri hangi yönde taşır?","steps":[{"t":"Taşınan madde","a":"Su ve mineral","d":"Monokot gövdede de ksilem, kökten alınan su ve suda çözünmüş mineralleri taşır. Bu inorganik maddeleri bitkinin üst kısımlarına ulaştırır."},{"t":"Taşıma yönü","a":"Kökten yapraklara (yukarı)","d":"Ksilemdeki taşıma tek yönlüdür ve aşağıdan yukarıya, yani kökten yapraklara doğru gerçekleşir. Terleme ve kök basıncı bu taşımayı sağlar."}],"ans":"Su ve mineralleri kökten yapraklara (aşağıdan yukarıya) taşır."},{"q":"Monokot gövdede floem (soymuk borusu) hangi maddeleri taşır ve hücre yapısı nasıldır?","steps":[{"t":"Taşınan madde","a":"Organik besin","d":"Monokot gövdede floem, yapraklarda fotosentezle üretilen organik besinleri (özellikle sakkaroz) taşır. Bu besinler bitkinin gereksinim duyan bölgelerine iletilir."},{"t":"Hücre yapısı","a":"Canlı kalburlu boru ve arkadaş hücre","d":"Floem; çekirdeğini kaybetmiş canlı kalburlu borular ile onlara eşlik eden çekirdekli arkadaş hücrelerden oluşur. Arkadaş hücreler taşımayı yönetir."}],"ans":"Organik besin (sakkaroz) taşır; canlı kalburlu boru ve arkadaş hücrelerden oluşur."},{"q":"Monokot gövdenin en dışındaki koruyucu dokunun adı ve görevi nedir?","steps":[{"t":"Dış doku","a":"En dışta epidermis","d":"Monokot gövdenin en dışını tek sıra hücreden oluşan epidermis örter. Bu doku gövdenin koruyucu örtüsüdür."},{"t":"Görevi","a":"Koruma ve su tutma","d":"Epidermis, üzerindeki kütikula tabakasıyla birlikte gövdeyi dış etkilerden korur ve su kaybını azaltır. Böylece bitkinin kurumasını önler."}],"ans":"Epidermis; gövdeyi korur ve kütikulasıyla su kaybını azaltır."},{"q":"Monokot demetlerinin kapalı olması bitkinin yara onarımı ve kalınlaşma yeteneğini nasıl sınırlar?","steps":[{"t":"Kapalı demet","a":"Kambiyum yok","d":"Monokot demetlerinde kambiyum bulunmadığı için yeni iletim dokusu ve ek hücre tabakaları üretilemez. Demet bir kez oluştuktan sonra gelişemez."},{"t":"Kalınlaşma sınırı","a":"Enine büyüme yok","d":"Kambiyum olmadığından gövde enine kalınlaşamaz ve ikincil büyüme gerçekleşmez. Bu nedenle gövde ince kalır."},{"t":"Onarım sınırı","a":"Yara kapatma sınırlı","d":"Kambiyum gibi sürekli bölünen bir doku olmadığı için monokotlar dikotlar kadar etkili biçimde yeni iletim dokusu üretip yaraları kapatamaz. Onarım yeteneği sınırlıdır."}],"ans":"Kambiyum eksikliği nedeniyle gövde enine kalınlaşamaz ve yeni iletim dokusu üretip yaraları onarma yeteneği sınırlıdır."},{"q":"Monokot gövdede temel doku (parankima) hangi görevleri üstlenir?","steps":[{"t":"Temel dokunun konumu","a":"Demetler arasını doldurur","d":"Monokot gövdede iletim demetleri temel parankima dokusu içine gömülüdür. Bu doku demetler arasındaki tüm boşluğu doldurur."},{"t":"Görevleri","a":"Depolama ve destek","d":"Temel parankima, su ve besin maddelerini depolar; gövdeye dolgunluk vererek destek sağlar. Kloroplast içeren hücreleri varsa fotosentez de yapabilir."}],"ans":"Demetler arasını doldurur; besin/su depolar, gövdeye destek verir ve gerekirse fotosentez yapar."},{"q":"Monokot gövde otsu yapısına rağmen yapraklarını ve çiçeklerini taşıyabiliyorsa bu desteği hangi yapılarla sağlar?","steps":[{"t":"Otsu gövdenin sorunu","a":"Odun yok ama destek gerekli","d":"Monokot gövde odun (ikincil ksilem) içermediği için yapısal desteğini başka kaynaklardan sağlamak zorundadır. Yine de yaprak ve çiçeklerini taşıyabilir."},{"t":"Destek kaynakları","a":"Sklerenkima ve turgor","d":"Demetleri saran sklerenkima kılıfları gövdeye mekanik dayanıklılık verir. Ayrıca parankima hücrelerinin su ile dolu olması (turgor basıncı) gövdeyi dik tutmaya yardımcı olur."}],"ans":"Demetleri saran sklerenkima kılıfları ve parankimanın turgor basıncı gövdeye destek sağlar."},{"q":"Monokot gövdede iletim demetlerinin dağınık olmasının taşıma açısından bir sakıncası var mıdır? Açıklayınız.","steps":[{"t":"Dağınık dizilim","a":"Demetler her yere yayılmış","d":"Monokot gövdede demetler tüm kesite dağılmıştır. Bu dağılım dikottaki düzenli halkadan farklıdır."},{"t":"Taşımaya etkisi","a":"Taşıma yine etkilidir","d":"Demetlerin her yere yayılması, su ve besinin gövdenin tüm bölgelerine kolayca ulaşmasını sağlar. Bu nedenle dağınık dizilim taşıma açısından önemli bir sakınca oluşturmaz; her demet bağımsız olarak taşımayı sürdürür."}],"ans":"Önemli bir sakınca yoktur; dağınık demetler gövdenin her bölgesine etkili taşıma sağlar."}],"zor":[{"q":"Monokot gövdede iletim demetlerinin kapalı (kambiyumsuz) olması bitkinin yaşam stratejisi açısından hangi avantaj ve dezavantajları doğurur?","steps":[{"t":"Dezavantaj","a":"İkincil büyüme yok","d":"Kambiyum bulunmadığı için monokotlar enine kalınlaşamaz, kalın odunsu gövdeler oluşturamaz. Bu, uzun ömürlü dev ağaçlara dönüşmelerini engeller ve mekanik dayanıklılıklarını sınırlar."},{"t":"Avantaj","a":"Hızlı büyüme ve ekonomi","d":"Kalın odun üretmeye enerji harcamadıkları için monokotlar hızla boylanıp kısa sürede üreme olgunluğuna ulaşabilir. Bu, otsu yaşam döngüsüne ve hızlı yayılmaya uygundur."},{"t":"Genel değerlendirme","a":"Stratejik denge","d":"Kambiyumsuzluk; uzun ömür ve büyük boyut açısından dezavantaj, hızlı büyüme ve düşük yapısal maliyet açısından avantaj sağlar. Birçok monokot bu hızlı ve otsu stratejiyle başarılı olmuştur."}],"ans":"Dezavantaj: enine kalınlaşamama ve sınırlı dayanıklılık; avantaj: düşük yapısal maliyetle hızlı büyüme ve erken üreme."},{"q":"Palmiye gibi bazı monokotlar tipik kambiyuma sahip olmadıkları halde nasıl kalınca gövdeler oluşturabilir? Bu büyümenin dikot ikincil büyümesinden farkı nedir?","steps":[{"t":"Sorun","a":"Kambiyumsuz ama kalın gövde","d":"Palmiye gibi bazı monokotlar klasik vasküler kambiyuma sahip değildir, yine de oldukça kalın gövdeler geliştirebilir. Bu durum açıklanması gereken bir özelliktir."},{"t":"Birincil kalınlaşma","a":"Birincil kalınlaşma meristemi çalışır","d":"Bu bitkilerde gövde ucuna yakın bir birincil kalınlaşma meristemi bulunur. Bu meristem hücre sayısını ve hacmini artırarak gövdeyi uçtayken kalınlaştırır; ayrıca hücre genişlemesi de katkı sağlar."},{"t":"Dikotla farkı","a":"Yeni iletim demeti üretmez","d":"Dikot ikincil büyümesi kambiyumla sürekli yeni ksilem-floem ekleyerek yıllar boyu kalınlaşma sağlar. Monokotta ise kalınlaşma çoğunlukla gövde tepesindeyken ve hücre genişlemesiyle olur; kalınlaştıktan sonra yeni iletim demeti eklenmez ve yıllık halka oluşmaz."}],"ans":"Birincil kalınlaşma meristemi ve hücre genişlemesiyle gövde uçtayken kalınlaşır; dikottan farkı kambiyumla sürekli yeni iletim dokusu üretip yıllık halka oluşturmamasıdır."},{"q":"Monokot gövdede iletim demetlerinin dağınık dağılımı ile dikot gövdede halka dizilimi arasındaki fark, gelişim (embriyolojik) açıdan hangi temel ayrıma dayanır?","steps":[{"t":"Çenek farkı","a":"Tohumdaki çenek sayısı farklı","d":"Monokotlar tohumda tek çenek (kotiledon), dikotlar iki çenek taşır. Bu temel embriyolojik fark, bitkinin tüm gelişim planını etkiler."},{"t":"Meristem organizasyonu","a":"Demet öncülleri farklı düzenlenir","d":"Embriyonik gelişim sırasında prokambiyum (demet öncülü) iplikleri monokotlarda temel dokuya dağınık, dikotlarda merkez çevresinde halka biçiminde düzenlenir. Demetlerin son dizilişi bu erken düzenlenmeyle belirlenir."},{"t":"Sonuç","a":"Diziliş farkı kökten gelir","d":"Böylece monokottaki dağınık ve dikottaki halka dizilimi, rastgele değil, embriyonik prokambiyum düzeninden ve iki gruptaki temel gelişim programı farkından kaynaklanır."}],"ans":"Fark, monokot/dikot embriyolarındaki prokambiyum (demet öncülü) dizilim programına dayanır; tek/iki çenekli gelişim planı demetlerin dağınık ya da halka biçiminde dizilmesini belirler."},{"q":"Monokot demetinde kambiyum bulunmaması, yara veya kesilme durumunda dikota kıyasla hangi onarım kısıtını doğurur ve bu monokotların yetiştiriciliğini nasıl etkiler?","steps":[{"t":"Dikottaki onarım","a":"Kambiyum yeni doku üretir","d":"Dikotlarda kambiyum sürekli bölünebildiği için yaralanan gövdede yeni iletim dokusu ve kallus üretilebilir; aşılama bu sayede başarılı olur."},{"t":"Monokottaki kısıt","a":"Yeni iletim dokusu üretilemez","d":"Monokotlarda kambiyum olmadığı için yaralı bölgede yeni iletim demeti oluşturulamaz. Kesilen demet bir daha yenilenemez ve onarım sınırlı kalır."},{"t":"Yetiştiriciliğe etkisi","a":"Aşılama zorlaşır","d":"Bu kısıt nedeniyle monokotlarda dikotlardaki gibi klasik aşı (kalem aşısı) genellikle başarılı olmaz. Bu yüzden monokotlar çoğunlukla tohum veya vejetatif (sürgün, soğan, rizom) yöntemlerle çoğaltılır."}],"ans":"Kambiyum yokluğu yeni iletim dokusu üretimini engeller; bu nedenle yara onarımı ve klasik aşılama zordur, monokotlar genelde tohum veya vejetatif yolla çoğaltılır."},{"q":"Bir mısır (monokot) ve bir ayçiçeği (dikot) gövdesinin enine kesiti karşılaştırıldığında, demet dizilişi ve kambiyum varlığı dışında temel doku bölgelenmesi açısından ne gibi farklar gözlenir?","steps":[{"t":"Dikot bölgelenmesi","a":"Net öz-korteks ayrımı","d":"Ayçiçeği gibi dikot gövdede demetler halka yaptığı için içte öz, dışta korteks net biçimde ayrılır ve aralarda öz kolları bulunur. Temel doku bölgelere ayrılmıştır."},{"t":"Monokot bölgelenmesi","a":"Tek tip temel doku","d":"Mısır gibi monokot gövdede demetler dağınık olduğu için öz, korteks ayrımı belirginleşmez. Demetler tek tip temel parankima dokusu içine gömülüdür ve öz kolu görülmez."},{"t":"Sonuç","a":"Bölgeli karşı homojen yapı","d":"Dikot gövde belirgin bölgelere ayrılmış (öz, korteks, öz kolları) bir yapı sunarken, monokot gövde demetler dışında daha homojen tek tip temel doku içerir. Bu, demet diziliş farkının doğrudan bir sonucudur."}],"ans":"Dikotta net öz-korteks-öz kolu bölgelenmesi vardır; monokotta demetler tek tip temel doku içine gömülüdür ve belirgin bölgelenme görülmez."},{"q":"Monokot gövdede her demeti saran sklerenkima kılıfı, ince ve otsu gövdenin mekanik dayanıklılığına nasıl katkı sağlar? Bu durum kambiyum yokluğunu kısmen nasıl telafi eder?","steps":[{"t":"Kılıfın yapısı","a":"Demet etrafında sert halka","d":"Monokot demetlerinin çevresi ölü, ligninleşmiş kalın çeperli sklerenkima hücrelerinden oluşan bir kılıfla sarılıdır. Bu kılıf demeti çevreleyen sert bir halka oluşturur."},{"t":"Mekanik katkı","a":"Gerilime ve eğilmeye direnç","d":"Gövdeye dağılmış çok sayıda sklerenkima kılıfı, gövdenin eğilme ve gerilme kuvvetlerine direnmesini sağlar. Demetlerin dağınık dağılımı bu destek noktalarının tüm kesite yayılmasına yol açar."},{"t":"Kambiyum yokluğunu telafi","a":"Odun yerine geçer","d":"Dikotlar dayanıklılığı kambiyumun ürettiği odundan alırken, monokotlar bunu sklerenkima kılıflarıyla sağlar. Böylece ikincil büyüme olmadan da, dağınık sert kılıflar sayesinde gövde dik ve dayanıklı kalır; bu kambiyum yokluğunu kısmen telafi eder."}],"ans":"Demetleri saran ligninli sklerenkima kılıfları gövdeye eğilme/gerilme direnci verir ve odunun (kambiyum) eksikliğini kısmen telafi ederek otsu gövdeyi dik tutar."},{"q":"Monokot gövdede ksilem boşluğu (protoksilem boşluğu) bulunması olgunlaşma sürecinde nasıl oluşur ve işlevsel anlamı nedir?","steps":[{"t":"Protoksilem","a":"İlk oluşan ksilem","d":"Demet gelişirken önce protoksilem adı verilen ilk ksilem elemanları oluşur. Bunlar gövde hâlâ boyuna uzarken görev yapan ince elemanlardır."},{"t":"Boşluk oluşumu","a":"Gerilmeyle yırtılır","d":"Gövde boyuna uzadıkça, esnemeyen protoksilem elemanları gerilip yırtılır ve geride sıvı dolu bir boşluk (protoksilem lakünası) bırakır. Bu boşluk monokot demetinin tabanında görülür."},{"t":"İşlevsel anlam","a":"Uzamaya uyum","d":"Bu boşluk, gövdenin boyuna uzaması sırasında oluşan gerilimin iletim sistemine zarar vermeden karşılanmasını sağlar. Olgun metaksilem ise uzama bittikten sonra asıl su iletimini üstlenir; böylece demet hem büyümeye uyum sağlar hem işlevini sürdürür."}],"ans":"Gövde uzarken protoksilemin gerilip yırtılmasıyla protoksilem boşluğu oluşur; bu, iletim sisteminin boyuna uzamaya zarar görmeden uyum sağlamasının işaretidir."},{"q":"Monokot ve dikot gövdelerdeki yapısal farklar (demet dizilişi, kambiyum, öz/korteks ayrımı) bir bütün olarak iki grubun ekolojik ve evrimsel başarısını nasıl şekillendirmiştir?","steps":[{"t":"Dikot stratejisi","a":"Kalınlaşma ve uzun ömür","d":"Dikotlar kambiyum ve halka demet dizilişi sayesinde odunlaşıp ağaç ve çalı olabilir. Bu, uzun ömür, büyük boy ve orman gibi yapısal egemenlik sağlar."},{"t":"Monokot stratejisi","a":"Hızlı, otsu, esnek yapı","d":"Monokotlar dağınık kapalı demetler ve sklerenkima kılıflarıyla hızlı büyüyen, esnek ve genellikle otsu gövdeler oluşturur. Bu, çayır, tarla ve hızlı kolonizasyona uygun bir stratejidir."},{"t":"Ekolojik-evrimsel sonuç","a":"Farklı nişlerde başarı","d":"İki yapısal model iki farklı yaşam stratejisini destekler: dikotlar kalıcı odunsu egemenlikte, monokotlar (otlar, tahıllar) hızlı yayılma ve yüksek üretkenlikte başarılıdır. Böylece yapısal farklar her iki grubun da farklı ekolojik nişlerde geniş çapta başarılı olmasını sağlamıştır."}],"ans":"Dikotların kambiyumlu odunsu yapısı uzun ömürlü egemenlik; monokotların kambiyumsuz, sklerenkima destekli otsu yapısı hızlı büyüme ve yayılma sağlar; bu yapısal modeller iki grubu farklı ekolojik nişlerde başarılı kılmıştır."},{"q":"Monokot demetinde ksilemin içte floemin dışta olduğu kollateral düzen, su ve besin taşınması açısından dikottakiyle aynı işlevsel mantığı taşır mı? Açıklayınız.","steps":[{"t":"Konum benzerliği","a":"Her ikisinde de ksilem içte","d":"Hem monokot hem dikot kollateral demette ksilem içte (merkeze doğru), floem dışta (yüzeye doğru) yer alır. Bu temel konum düzeni iki grupta da aynıdır."},{"t":"İşlevsel mantık","a":"Aynı taşıma mantığı","d":"Bu düzende ksilemin merkeze yakın olması su sütununa destek ve koruma sağlar; floemin dışta olması besinin büyüyen çevre dokulara kolay ulaşmasını sağlar. Bu işlevsel mantık her iki grupta da geçerlidir."},{"t":"Temel fark","a":"Kambiyum varlığı","d":"Tek temel fark, dikotta ksilem-floem arasında kambiyum bulunup ikincil büyüme yapılabilmesi, monokotta ise kambiyum olmaması ve demetin kapalı kalmasıdır. Taşıma mantığı aynı, gelişim potansiyeli farklıdır."}],"ans":"Evet, ksilem içte-floem dışta düzeniyle taşıma mantığı aynıdır; tek fark dikotta arada kambiyum bulunup ikincil büyüme yapılabilmesidir."},{"q":"Monokot gövdede ikincil büyümenin olmaması, gövdenin yaşa bağlı olarak iletim kapasitesini nasıl etkiler ve bitki bunu hangi yapısal düzenlemeyle dengeler?","steps":[{"t":"İletim kapasitesi sorunu","a":"Yeni demet eklenemez","d":"Dikotlarda kambiyum her yıl yeni iletim dokusu ekleyerek büyüyen bitkinin artan su ve besin ihtiyacını karşılar. Monokotta kambiyum olmadığı için olgunlaştıktan sonra yeni iletim demeti eklenemez."},{"t":"Erken bol demet üretimi","a":"Başlangıçta çok demet oluşturulur","d":"Bu kısıtı dengelemek için monokot gövde, gelişiminin erken aşamasında temel doku içine çok sayıda demet yerleştirir. Demetlerin dağınık ve bol olması, sonradan eklenememesini telafi eden bir tasarımdır."},{"t":"Sonuç","a":"Sabit ama yeterli kapasite","d":"Böylece monokot gövde, başlangıçta oluşturduğu bol ve dağınık demetlerle yaşamı boyunca yeterli iletim kapasitesine sahip olur. İletim kapasitesi yaşla artmaz ama erken yatırım sayesinde bitkinin ihtiyacını karşılayacak düzeyde sabit kalır."}],"ans":"Yeni demet eklenemediği için iletim kapasitesi yaşla artmaz; bitki bunu erken gelişimde çok sayıda dağınık demet oluşturarak dengeler."},{"q":"Monokot gövdede temel doku içine gömülü dağınık demetlerin, ince gövdede yük dağılımı (mekanik) açısından bir mühendislik avantajı var mıdır?","steps":[{"t":"Yük dağılımı sorunu","a":"İnce gövde eğilmeye açık","d":"Monokot gövde ince ve odunsuz olduğu için rüzgar ve kendi ağırlığı altında eğilme kuvvetlerine maruz kalır. Bu kuvvetlerin gövde boyunca dengeli karşılanması gerekir."},{"t":"Dağınık demet etkisi","a":"Sert noktalar tüm kesite yayılır","d":"Sklerenkima kılıflı sert demetler tüm kesite dağıldığı için, eğilme kuvvetine direnen sert bölgeler gövdenin yalnızca bir halkasında değil her yerine yayılmış olur. Bu, kesitin her yönden gelen yüke benzer şekilde direnmesini sağlar."},{"t":"Mühendislik avantajı","a":"Kompozit kiriş etkisi","d":"Dağınık sert demetlerin yumuşak parankima içine gömülü olması, gövdeyi kompozit bir kirişe benzetir; sert lifler yükü taşırken yumuşak matris esneklik sağlar. Böylece ince gövde hem dayanıklı hem esnek olur ve kolay kırılmadan eğilip doğrulabilir."}],"ans":"Evet; sklerenkima kılıflı demetlerin tüm kesite dağılması, yumuşak parankima içinde kompozit kiriş etkisi oluşturarak ince gövdeye her yönden dayanıklılık ve esneklik kazandırır."},{"q":"Monokot gövdede metaksilem ve protoksilemin oluşum sırası ile işlevsel devir teslimini açıklayınız.","steps":[{"t":"Protoksilem","a":"Önce ve uzama sırasında","d":"Protoksilem, demetin ilk olgunlaşan ksilem elemanıdır ve gövde hâlâ boyuna uzarken görev yapar. İnce ve esneyebilen halkalı/sarmal çeperlere sahiptir, böylece uzayan dokuyla bir süre birlikte gerilebilir."},{"t":"Metaksilem","a":"Sonra ve uzama bitince","d":"Metaksilem, gövdenin boyuna uzaması büyük ölçüde tamamlandıktan sonra olgunlaşan ksilem elemanıdır. Daha geniş çaplı ve kalın çeperlidir, bu yüzden daha etkili su iletimi yapar ama esneme yeteneği yoktur."},{"t":"İşlevsel devir teslim","a":"Görev metaksileme geçer","d":"Uzama sürerken protoksilem su taşır; ancak uzama nedeniyle protoksilem yırtılıp boşluk bırakınca asıl iletim görevi olgunlaşan metaksileme devredilir. Böylece demet, hem büyüme aşamasında hem olgunlukta kesintisiz su iletimini sürdürür."}],"ans":"Önce protoksilem (uzama sırasında, esnek) görev yapar; uzama bitince geniş çaplı metaksilem olgunlaşır ve asıl su iletim görevini devralır."},{"q":"Monokot gövdenin genellikle ince ve uzun kalması, bu bitkilerin su iletimi (terleme-gerilim) açısından dikot ağaçlara göre hangi sınırlamayı yaşar?","steps":[{"t":"Dikot ağaç durumu","a":"Çok katmanlı geniş ksilem","d":"Dikot ağaçlarda kambiyum yıllarca ksilem üreterek geniş ve çok katmanlı bir su iletim sistemi oluşturur. Bu, yüksek ağaçlarda bile büyük su kütlelerini yapraklara taşımayı mümkün kılar."},{"t":"Monokot sınırlaması","a":"Sabit sayıda demet","d":"Monokotlarda kambiyum olmadığı için ksilem miktarı başlangıçtaki demetlerle sınırlıdır ve artırılamaz. Bu, çok yükseğe su taşıma kapasitesini kısıtlar."},{"t":"Sonuç","a":"Aşırı boylanma sınırlı","d":"Sabit iletim kapasitesi ve enine kalınlaşamama nedeniyle, tipik otsu monokotlar dikot ağaçlar kadar yükselip büyük su sütunlarını taşıyamaz. Bu yüzden çoğu monokot ince, otsu ve sınırlı boyda kalır; palmiye gibi istisnalar özel yapısal uyarlamalarla bu sınırı kısmen aşar."}],"ans":"Kambiyumsuzluk ksilem miktarını sabit tuttuğu için su iletim kapasitesi artırılamaz; bu da tipik monokotların dikot ağaçlar gibi çok yükselip büyük su sütunu taşımasını sınırlar."},{"q":"Monokot gövdede iletim demetlerinin sayısının dış kenara doğru artması (yoğunlaşması) bazı türlerde gözlenir. Bu dağılım örüntüsünün işlevsel anlamı ne olabilir?","steps":[{"t":"Gözlenen örüntü","a":"Kenara doğru daha sık demet","d":"Bazı monokot gövdelerde demetler tam dağınık olmakla birlikte, gövdenin dış kenarına yakın bölgede merkeze göre daha sık ve küçük demetler bulunur. Merkeze doğru demetler seyrekleşir."},{"t":"Mekanik anlam","a":"Eğilme direnci kenarda yüksek olmalı","d":"Bir kirişte eğilme gerilmeleri en çok dış yüzeye yakın bölgede oluşur. Sert demetlerin kenara yoğunlaşması, gövdenin eğilmeye en çok zorlanan dış bölgesini güçlendirir ve dayanıklılığı artırır."},{"t":"İşlevsel sonuç","a":"Malzeme ekonomisiyle dayanıklılık","d":"Bu örüntü, sınırlı sert dokuyu en çok gereken dış bölgeye yerleştirerek malzeme ekonomisi sağlar. Böylece ince gövde, fazladan kalınlaşmaya gerek kalmadan eğilmeye karşı yüksek direnç kazanır."}],"ans":"Sert demetlerin dış kenara yoğunlaşması, eğilme gerilmesinin en yüksek olduğu bölgeyi güçlendirir; bu, malzeme ekonomisiyle gövdeye yüksek eğilme direnci kazandırır."},{"q":"Monokot ve dikot gövde yapısındaki farklar göz önüne alındığında, neden tahıllar (buğday, mısır, pirinç) gibi monokotlar tarımsal üretimde hızlı ve verimli olabilirken orman ekosistemlerine odun sağlayan ağaçların çoğunun dikot olduğu açıklanabilir mi?","steps":[{"t":"Monokot tahıllar","a":"Hızlı, otsu, tek mevsim","d":"Tahıllar kambiyumsuz, otsu monokotlardır; enine kalınlaşmaya enerji harcamadan tek bir mevsimde hızla boylanıp tane (tohum) üretebilir. Bu, kısa sürede yüksek ürün veren tarımsal verimlilik için idealdir."},{"t":"Dikot ağaçlar","a":"Kambiyumla odun biriktirir","d":"Orman ağaçlarının çoğu dikottur; kambiyumları yıllarca ikincil ksilem (odun) üreterek kalın, dayanıklı gövdeler oluşturur. Bu odun hem ağacın uzun ömürlü egemenliğini hem de insan için kereste kaynağını sağlar."},{"t":"Sonuç","a":"Yapı kullanım alanını belirler","d":"Monokotların kambiyumsuz hızlı-otsu yapısı onları kısa döngülü gıda üretimine, dikotların kambiyumlu odunsu yapısı ise uzun ömürlü odun ve orman oluşumuna uygun kılar. Böylece yapısal farklar iki grubun ekonomik ve ekolojik rollerini doğrudan belirler."}],"ans":"Evet; monokotların kambiyumsuz otsu yapısı kısa döngüde hızlı tane üretimine (tahıl), dikotların kambiyumlu odunsu yapısı uzun ömürlü odun/orman oluşumuna uygundur; yapı, kullanım alanını belirler."}]}},"ikincilBuyume":{"ilkokul":{"kolay":[{"q":"Ağaçların gövdesi yıllar geçtikçe kalınlaşır. Bu kalınlaşmayı sağlayan olaya kısaca ne ad verilir?","steps":[{"t":"Büyüme yönü","a":"Enine kalınlaşma","d":"Bitkiler uzunlamasına büyürken bir yandan da gövdeleri enine (yanlara doğru) kalınlaşabilir. Ağaçlarda her yıl gövde biraz daha kalın hale gelir."},{"t":"Olayın adı","a":"İkincil büyüme","d":"Gövdenin yıllar içinde enine kalınlaşmasına ikincil büyüme denir. Bu sayede koca çınar ağaçlarının gövdesi çok kalın olabilir."}],"ans":"İkincil büyüme (enine kalınlaşma)"},{"q":"Bir ağacın kesilmiş gövdesinde gördüğümüz iç içe halkalara ne ad verilir?","steps":[{"t":"Kesitte görünen","a":"İç içe daireler","d":"Bir ağaç kütüğüne yukarıdan baktığımızda merkezden dışa doğru iç içe geçmiş daireler görürüz. Bunlar ağacın her yıl ekledigi katmanlardır."},{"t":"Halkaların adı","a":"Yıllık halkalar","d":"Bu iç içe dairelere yıllık halka denir. Her yıl yeni bir halka eklendiği için bunlar ağacın büyüme izleridir."}],"ans":"Yıllık halkalar"},{"q":"Bir ağacın yaşını öğrenmek için kesilmiş gövdesinde neyi sayarız?","steps":[{"t":"Sayılacak yapı","a":"Halkalar","d":"Kesilmiş bir ağaç gövdesinde merkezden dışa doğru çok sayıda halka bulunur. Bu halkaları teker teker sayabiliriz."},{"t":"Yaş ilişkisi","a":"Her halka bir yıl","d":"Genellikle her yıllık halka bir yılı gösterir. Halkaları sayarsak ağacın yaklaşık kaç yaşında olduğunu buluruz."}],"ans":"Yıllık halkaları sayarız"},{"q":"Çınar veya meşe gibi ağaçlarda gövde her yıl kalınlaşırken, mısır veya buğday gibi bitkilerin gövdesi yıllarca kalınlaşmaz. Bu durum hangi grupta gözlenir?","steps":[{"t":"Kalınlaşan bitkiler","a":"Ağaçlar","d":"Çınar ve meşe gibi ağaçların gövdeleri her yıl biraz daha kalınlaşarak yıllık halkalar oluşturur. Bu yüzden çok kalın gövdeleri olabilir."},{"t":"Kalınlaşmayan bitkiler","a":"Mısır, buğday gibi otsular","d":"Mısır ve buğday gibi bitkilerin gövdesi yıllar boyu kalınlaşmaz. Enine kalınlaşma asıl olarak ağaçlarda gözlenen bir özelliktir."}],"ans":"Ağaçlarda gözlenir"},{"q":"Ağacın gövdesini en dıştan saran, onu koruyan sert tabakaya halk arasında ne ad verilir?","steps":[{"t":"En dış tabaka","a":"Sert örtü","d":"Ağaç gövdesinin en dışında sert ve kalın bir örtü bulunur. Bu örtü ağacı dış etkilerden korur."},{"t":"Halk dilindeki adı","a":"Kabuk","d":"Ağacın dışını saran bu koruyucu sert tabakaya kabuk denir. Kabuk ağacı zedelenmeye ve kurumaya karşı korur."}],"ans":"Kabuk"}],"zor":[{"q":"Bir ağaç gövdesinde merkeze yakın halkalar daha koyu ve serttir, dışa doğru olan halkalar ise daha açıktır. Merkeze yakın koyu kısım ağacın hangi dönemine aittir?","steps":[{"t":"Halkaların yeri","a":"Merkez en eski","d":"Ağaç gövdesinde halkalar içten dışa doğru sıralanır. Merkezdeki halkalar en önce oluşan, en eski halkalardır."},{"t":"Koyu kısmın anlamı","a":"İlk yıllar","d":"Merkeze yakın koyu ve sert kısım ağacın ilk yıllarında, yani gençken oluşan odundur. Dışa doğru gidildikçe daha yeni halkalara ulaşılır."}],"ans":"Ağacın ilk (genç) yıllarına aittir"},{"q":"Bir ağacın gövdesinde 8 tane yıllık halka sayıldı. Bu ağaç yaklaşık kaç yaşındadır ve bunu nasıl anlarız?","steps":[{"t":"Halka sayısı","a":"8 halka","d":"Gövdede merkezden dışa doğru 8 adet yıllık halka sayılmıştır. Her halka ağacın bir büyüme yılını temsil eder."},{"t":"Yaş hesabı","a":"Yaklaşık 8 yaş","d":"Genellikle her yılda bir halka oluştuğu için halka sayısı yaşı verir. 8 halka olduğundan ağaç yaklaşık 8 yaşındadır."}],"ans":"Yaklaşık 8 yaşındadır"},{"q":"Ağacın gövdesinin kalınlaşması için gövdenin içinde sürekli yeni hücreler üretilmesi gerekir. Bu yeni hücreleri üreten, ince ve canlı bir tabaka olmalıdır. Bu tabakanın görevi nedir?","steps":[{"t":"Kalınlaşmanın kaynağı","a":"Yeni hücreler","d":"Bir gövdenin kalınlaşması için sürekli yeni hücrelerin oluşması gerekir. Bu hücreler gövdenin belli bir bölgesinde üretilir."},{"t":"Üretici tabaka","a":"Bölünen canlı tabaka","d":"Gövdenin içinde bölünerek yeni hücre üreten ince ve canlı bir tabaka vardır. Bu tabaka durmadan hücre üreterek gövdeyi kalınlaştırır."}],"ans":"Gövdeyi kalınlaştıran yeni hücreleri üretmek"},{"q":"İki farklı ağaç kesildi. Birinin gövdesinde dar halkalar, diğerininkinde geniş halkalar var. Geniş halkalı ağaç hangi koşulda büyümüş olabilir?","steps":[{"t":"Halka genişliği","a":"Büyümeyle ilgili","d":"Halkaların genişliği ağacın o yıl ne kadar büyüdüğünü gösterir. Geniş halka çok büyüme, dar halka az büyüme anlamına gelir."},{"t":"İyi koşul","a":"Bol su ve güneş","d":"Su, ışık ve besinin bol olduğu yıllarda ağaç daha çok büyür ve geniş halka oluşturur. Geniş halkalı ağaç büyümek için elverişli koşullarda yaşamış olabilir."}],"ans":"Su, ışık ve besinin bol olduğu iyi koşullarda büyümüştür"},{"q":"Bir ağacın kabuğu halka şeklinde tamamen soyulursa ağaç zamanla kuruyabilir. Bunun nedeni kabuğun hemen altındaki taşıyan boruların zarar görmesi olabilir mi?","steps":[{"t":"Kabuğun altı","a":"Taşıyan borular","d":"Ağaç kabuğunun hemen altında, yaprakta yapılan besini taşıyan boru benzeri yapılar bulunur. Bu borular besinin köklere ulaşmasını sağlar."},{"t":"Soyulmanın etkisi","a":"Besin taşınamaz","d":"Kabuk halka şeklinde soyulursa bu besin boruları kopar ve besin alt kısımlara taşınamaz. Bu yüzden ağaç zamanla zayıflayıp kuruyabilir."}],"ans":"Evet, besin taşıyan borular zarar gördüğü için kuruyabilir"}]},"ortaokul":{"kolay":[{"q":"Bitkilerde gövdenin enine kalınlaşmasını sağlayan, içe odun dışa soymuk üreten halka biçimindeki bölünür dokunun adı nedir?","steps":[{"t":"Kalınlaşmanın nedeni","a":"Bölünür doku","d":"Gövdenin enine kalınlaşması için sürekli bölünüp yeni hücre üreten bir doku gerekir. Bu dokuya bölünür (meristem) doku denir."},{"t":"Konum ve adı","a":"Vasküler kambiyum","d":"Gövdede ksilem ile floem arasında halka biçiminde uzanan bu dokuya vasküler kambiyum (demet kambiyumu) denir. İçe doğru odun, dışa doğru soymuk üretir."}],"ans":"Vasküler kambiyum (demet kambiyumu)"},{"q":"Vasküler kambiyum içe doğru hangi dokuyu, dışa doğru hangi dokuyu üretir?","steps":[{"t":"İçe üretim","a":"İkincil ksilem","d":"Kambiyum gövdenin iç tarafına doğru ikincil ksilem üretir. Halk dilinde buna odun denir ve gövdenin büyük kısmını oluşturur."},{"t":"Dışa üretim","a":"İkincil floem","d":"Kambiyum dış tarafa doğru ise ikincil floem üretir. Buna soymuk denir ve yaprakta üretilen besini taşır."}],"ans":"İçe ikincil ksilem (odun), dışa ikincil floem (soymuk)"},{"q":"Ağaç gövdesinde her yıl bir tane oluşan ve ağacın yaşının belirlenmesini sağlayan halkalara ne denir?","steps":[{"t":"Oluşma sıklığı","a":"Yılda bir","d":"Kambiyumun mevsimlere göre farklı hızda hücre üretmesi sonucu her yıl bir halka oluşur. İlkbaharda hızlı, yazın yavaş üretim halkaları meydana getirir."},{"t":"Adı ve kullanımı","a":"Yıllık halka","d":"Bu halkalara yıllık halka denir. Halkalar sayılarak ağacın yaşı yaklaşık olarak belirlenebilir."}],"ans":"Yıllık halkalar"},{"q":"Mantar kambiyumu (fellojen) ağaç gövdesinde hangi koruyucu yapının oluşmasını sağlar?","steps":[{"t":"Fellojenin görevi","a":"Mantar üretimi","d":"Mantar kambiyumu (fellojen) gövdenin dış kısmında bulunan bir bölünür dokudur. Dışa doğru mantar (peridermin bir parçası) hücreleri üretir."},{"t":"Oluşan yapı","a":"Periderm","d":"Fellojenin ürettiği tabakalar birlikte peridermi oluşturur. Periderm, eski epidermisin yerini alarak gövdeyi koruyan kabuk yapısının bir bölümüdür."}],"ans":"Periderm (mantar tabakası / kabuk)"},{"q":"Mısır, buğday ve zambak gibi tek çenekli (monokot) bitkilerde genellikle gözlenmeyen büyüme türü hangisidir?","steps":[{"t":"Büyüme türleri","a":"Boyca ve enine","d":"Bitkiler hem boyca uzar hem de bazıları enine kalınlaşabilir. Enine kalınlaşma kambiyum sayesinde gerçekleşen ikincil büyümedir."},{"t":"Monokotlarda durum","a":"Kambiyum yok","d":"Tek çenekli bitkilerde genellikle vasküler kambiyum bulunmaz. Bu nedenle bu bitkilerde ikincil büyüme (enine kalınlaşma) genellikle gözlenmez."}],"ans":"İkincil büyüme (enine kalınlaşma)"}],"zor":[{"q":"Bir ağaç gövdesi kesitinde merkeze yakın koyu renkli \"öz odun\" ve dışa yakın açık renkli \"diri odun\" ayırt ediliyor. Bu iki bölgenin işlevsel farkı nedir?","steps":[{"t":"Diri odun","a":"İletim yapar","d":"Dışa yakın, açık renkli diri odun genç ksilem hücrelerinden oluşur. Bu bölge hâlâ su ve mineral taşıma görevini sürdürür."},{"t":"Öz odun","a":"İletim yapmaz","d":"Merkeze yakın koyu öz odun yaşlanmış, iletim yapmayan ksilemdir. Tıkanmış ve reçinelerle dolmuş olduğundan artık taşıma yapmaz, gövdeye destek sağlar."},{"t":"Sonuç","a":"Görev farkı","d":"Diri odun aktif iletim, öz odun ise sadece destek işlevi görür. Yıllar geçtikçe diri odunun iç kısımları öz oduna dönüşür."}],"ans":"Diri odun su iletir, öz odun iletim yapmaz yalnızca destek sağlar"},{"q":"İlkbaharda oluşan odun hücreleri büyük ve açık renkli, yaz sonunda oluşanlar küçük ve koyu olur. Bu farklılık yıllık halkaların görünmesini nasıl sağlar?","steps":[{"t":"İlkbahar odunu","a":"Geniş hücreler","d":"İlkbaharda su bol ve büyüme hızlıdır, bu yüzden kambiyum geniş çaplı, ince çeperli açık renkli hücreler üretir. Bu bölge halkanın açık kısmını oluşturur."},{"t":"Yaz odunu","a":"Dar hücreler","d":"Yaz sonuna doğru büyüme yavaşlar ve hücreler küçük, kalın çeperli, koyu renkli olur. Bu bölge halkanın koyu kısmını oluşturur."},{"t":"Halka oluşumu","a":"Açık-koyu sınır","d":"Açık ilkbahar odunu ile koyu yaz odunu arasındaki keskin sınır bir yıllık halkayı belirginleştirir. Her yıl bir açık-koyu çift halka oluşur."}],"ans":"İlkbahar odunu açık, yaz odunu koyu olduğu için halkalar belirginleşir"},{"q":"Ağaç gövdesinin kabuğunda küçük gözenekler (lentiseller) bulunur. Bu yapıların işlevi nedir ve neden gereklidir?","steps":[{"t":"Kabuğun özelliği","a":"Geçirimsiz","d":"Gövdeyi saran periderm mantarlı, su ve gaz geçirmez bir yapıdır. Bu durum içteki canlı hücrelerin gaz alışverişini engelleyebilir."},{"t":"Lentisellerin görevi","a":"Gaz değişimi","d":"Lentiseller kabuktaki gevşek yapılı küçük gözeneklerdir. Bu gözenekler içteki canlı dokuların oksijen alıp karbondioksit vermesini sağlar."},{"t":"Gereklilik","a":"Solunum","d":"Stomalar yalnızca yapraklarda ve genç dokularda bulunduğundan, kalınlaşmış gövde lentisellere ihtiyaç duyar. Böylece odunsu gövdedeki hücreler solunumunu sürdürür."}],"ans":"Lentiseller kalınlaşmış gövdede gaz alışverişini (solunumu) sağlar"},{"q":"Bir bitkide hem vasküler kambiyum hem de mantar kambiyumu (fellojen) çalışmaktadır. Bu iki kambiyumun ürettiği yapılar nasıl farklılık gösterir?","steps":[{"t":"Vasküler kambiyum","a":"İletim dokuları","d":"Vasküler kambiyum içe ikincil ksilem (odun), dışa ikincil floem (soymuk) üretir. Bu yapılar su ve besin iletiminden sorumludur."},{"t":"Mantar kambiyumu","a":"Koruyucu doku","d":"Mantar kambiyumu (fellojen) ise dışa mantar dokusu üreterek peridermi oluşturur. Bu yapı iletim değil koruma görevi görür."},{"t":"Genel sonuç","a":"Farklı görevler","d":"Vasküler kambiyum iletim ve gövde hacmini artırır, fellojen ise dış koruyucu kabuğu yeniler. İkisi birlikte ağacın hem kalınlaşmasını hem korunmasını sağlar."}],"ans":"Vasküler kambiyum iletim dokuları, fellojen koruyucu periderm üretir"},{"q":"Tek çenekli bir palmiye ağacı gövde çapı zamanla biraz artabilir, ancak çınar gibi gerçek bir ikincil büyüme göstermez. Bunun temel nedeni nedir?","steps":[{"t":"Çınarda durum","a":"Kambiyum var","d":"Çınar gibi çift çenekli odunsu bitkilerde halka biçiminde vasküler kambiyum bulunur. Bu kambiyum sürekli odun ve soymuk üreterek düzenli ikincil büyüme sağlar."},{"t":"Palmiyede durum","a":"Kambiyum yok","d":"Palmiye tek çenekli olduğu için gerçek bir vasküler kambiyumu yoktur. Bu yüzden çınardaki gibi yıllık halkalı düzenli kalınlaşma gösteremez."},{"t":"Sonuç","a":"Sınırlı artış","d":"Palmiyedeki çap artışı mevcut hücrelerin büyümesi ve dağınık demetlerin gelişmesiyle olur, kambiyum kaynaklı değildir. Bu nedenle gerçek ikincil büyüme sayılmaz."}],"ans":"Tek çenekli olduğu için vasküler kambiyumu yoktur"}]},"lise":{"kolay":[{"q":"İkincil büyümeden sorumlu vasküler kambiyumun çift çenekli bir gövdedeki konumu ve ürettiği dokular nelerdir?","steps":[{"t":"Konum","a":"Ksilem-floem arası","d":"Vasküler kambiyum, iletim demetlerinde birincil ksilem ile birincil floem arasında yer alan ince bir meristem tabakasıdır. Demetler arası kambiyumla birleşerek tam bir halka oluşturur."},{"t":"Üretim yönü","a":"İçe ve dışa","d":"Kambiyum hücreleri çift yönlü bölünür. İçe doğru ikincil ksilem, dışa doğru ikincil floem üretir."},{"t":"Sonuç","a":"Çap artışı","d":"Üretilen ikincil dokular gövde çapını artırır. Böylece bitki yıllar içinde enine kalınlaşır."}],"ans":"Ksilem-floem arasında yer alır; içe ikincil ksilem, dışa ikincil floem üretir"},{"q":"Vasküler kambiyumun ürettiği ikincil ksilem ve ikincil floem miktarları neden farklıdır ve bu durumun ağaç gövdesindeki gözle görülür sonucu nedir?","steps":[{"t":"Üretim oranı","a":"Ksilem daha fazla","d":"Vasküler kambiyum içe doğru, dışa doğru ürettiğinden çok daha fazla ikincil ksilem üretir. Bu nedenle odun gövdenin büyük kısmını oluşturur."},{"t":"Floem miktarı","a":"Daha az ve dışta","d":"İkincil floem daha az üretilir ve sürekli dışa itildiğinden eski floem ezilir. Bu yüzden floem ince bir tabaka olarak kabuğun iç kısmında kalır."},{"t":"Görülür sonuç","a":"Odun çoğunlukta","d":"Sonuçta gövdenin neredeyse tamamı odundan oluşur, kabuk ince kalır. Bir ağaç gövdesinin büyük kütlesi ikincil ksilemdir."}],"ans":"Ksilem daha çok üretilir, bu yüzden gövdenin büyük kısmı odundan oluşur"},{"q":"Periderm hangi tabakalardan oluşur ve birincil dokulardaki epidermisin yerini neden alır?","steps":[{"t":"Periderm bileşenleri","a":"Üç tabaka","d":"Periderm; mantar kambiyumu (fellojen), dışa ürettiği mantar dokusu (fellem) ve içe ürettiği fellodermden oluşur. Bu üçlü yapı gövdenin dış koruyucu örtüsünü meydana getirir."},{"t":"Epidermisin durumu","a":"Yırtılır","d":"İkincil büyümeyle gövde kalınlaştıkça ince epidermis gerilip yırtılır ve işlevini yitirir. Bu nedenle yeni bir koruyucu örtüye ihtiyaç doğar."},{"t":"Yer değiştirme","a":"Periderm devralır","d":"Fellojenin ürettiği periderm, yırtılan epidermisin koruma görevini üstlenir. Mantarlaşmış hücreler su kaybını ve mikrop girişini engeller."}],"ans":"Fellojen, mantar (fellem) ve fellodermden oluşur; yırtılan epidermisin yerini alır"},{"q":"Bir ağaç gövdesinin enine kesitinde merkezden dışa doğru başlıca dokular nasıl sıralanır?","steps":[{"t":"Merkez","a":"Öz ve odun","d":"Gövdenin en içinde öz, onu çevreleyen geniş bölgede ise yıllık halkalardan oluşan ikincil ksilem (odun) bulunur. Bu odun gövdenin büyük kütlesini kaplar."},{"t":"Orta sınır","a":"Kambiyum","d":"Odunun dış sınırında ince bir vasküler kambiyum halkası yer alır. Bu halka içe ksilem dışa floem üreterek dokuları ayırır."},{"t":"Dış kısım","a":"Floem ve periderm","d":"Kambiyumun dışında ikincil floem, en dışta ise periderm (kabuk) bulunur. Böylece içten dışa odun-kambiyum-floem-periderm sıralaması oluşur."}],"ans":"İçten dışa: öz, ikincil ksilem (odun), kambiyum, ikincil floem, periderm"},{"q":"Yıllık halkalardan oluşan odunda öz odun ile diri odun arasındaki temel işlevsel fark nedir?","steps":[{"t":"Diri odun","a":"Aktif iletim","d":"Diri odun, gövdenin dış kısmındaki genç ksilemdir ve su ile mineral iletimini aktif olarak sürdürür. Genellikle açık renklidir."},{"t":"Öz odun","a":"İletim yok","d":"Öz odun merkeze yakın, yaşlanmış ksilemdir; iletim borularının tıkanmasıyla iletim işlevini yitirmiştir. Reçine ve tanen birikimiyle koyu renk alır."},{"t":"Ortak rol","a":"Destek","d":"Her ikisi de gövdeye mekanik destek sağlar. Ancak yalnızca diri odun su taşıdığından, yaşlı ağaçlarda öz odun yalnızca destek görevi görür."}],"ans":"Diri odun su iletir; öz odun iletim yapmaz, yalnızca destek sağlar"},{"q":"Lentiseller peridermin neresinde bulunur ve hangi işlevi yerine getirir?","steps":[{"t":"Periderm sorunu","a":"Geçirimsizlik","d":"Periderm mantarlaşmış hücrelerden oluştuğu için su ve gaz geçirmez. Bu durum gövdedeki canlı hücrelerin gaz alışverişini engeller."},{"t":"Lentisel yapısı","a":"Gevşek hücreler","d":"Lentiseller peridermde gevşek dizilmiş, hücreler arası boşlukları bol olan küçük bölgelerdir. Genellikle gövde yüzeyinde mercimek biçimli kabartılar olarak görülür."},{"t":"İşlev","a":"Gaz değişimi","d":"Bu gevşek bölgeler iç dokuların atmosferle gaz alışverişi yapmasını sağlar. Böylece kalınlaşmış gövdedeki hücreler solunumu sürdürebilir."}],"ans":"Peridermde yer alır ve gövdenin gaz alışverişini (solunumunu) sağlar"},{"q":"Çift çenekli odunsu bitkiler düzenli ikincil büyüme gösterirken tek çenekli bitkilerde bunun genellikle görülmemesinin nedeni nedir?","steps":[{"t":"Çift çenekliler","a":"Halka demetler","d":"Çift çeneklilerde iletim demetleri düzenli bir halka şeklinde dizilir ve aralarında kambiyum oluşabilir. Bu kambiyum tam bir halkaya dönüşerek ikincil büyüme sağlar."},{"t":"Tek çenekliler","a":"Dağınık demetler","d":"Tek çeneklilerde iletim demetleri gövde içinde dağınık dizilmiştir ve genellikle kambiyum içermez. Bu nedenle düzenli bir kambiyum halkası oluşamaz."},{"t":"Sonuç","a":"İkincil büyüme yok","d":"Kambiyum halkası oluşmadığından tek çeneklilerde tipik ikincil büyüme görülmez. Bu bitkiler genellikle yalnızca birincil büyümeyle gelişir."}],"ans":"Tek çeneklilerde demetler dağınık ve kambiyum yoktur, bu yüzden ikincil büyüme görülmez"},{"q":"Demetler arası kambiyum (interfasiküler kambiyum) ikincil büyümede hangi rolü üstlenir?","steps":[{"t":"Başlangıç durumu","a":"Demet içi kambiyum","d":"Başlangıçta kambiyum yalnızca iletim demetlerinin içinde, ksilem ile floem arasında bulunur. Buna demet içi (fasiküler) kambiyum denir."},{"t":"Yeni oluşum","a":"Demetler arası","d":"İkincil büyüme başlarken demetler arasındaki parankima hücreleri de bölünme yeteneği kazanır. Böylece demetler arası (interfasiküler) kambiyum oluşur."},{"t":"Birleşme","a":"Tam halka","d":"Demet içi ve demetler arası kambiyum birleşerek kesintisiz bir kambiyum halkası oluşturur. Bu sayede gövde her yönde eşit kalınlaşabilir."}],"ans":"Demet içi kambiyumla birleşip kesintisiz kambiyum halkasını tamamlar"},{"q":"İkincil büyüme sırasında ilk floem (birincil floem) genellikle ezilip görünmez hale gelirken ksilem korunur. Bunun nedeni nedir?","steps":[{"t":"Üretim yönü","a":"Dışa floem","d":"Vasküler kambiyum floemi dışa doğru üretir, bu yüzden eski floem sürekli dışarıya doğru itilir. En eski birincil floem en dışta kalır."},{"t":"Floemin yapısı","a":"İnce çeperli","d":"Floem hücreleri ince çeperli ve yumuşaktır. Dış katmanların basıncı altında ezilerek tanınamaz hale gelir."},{"t":"Ksilemin yapısı","a":"Kalın çeperli","d":"Ksilem ise içe doğru üretilir ve lignin içeren kalın, sert çeperlere sahiptir. Bu sağlam yapı sayesinde ezilmez ve gövdede birikerek korunur."}],"ans":"Floem ince çeperli olup ezilir, ksilem kalın çeperli olduğundan korunur"},{"q":"Bir ağacın gövdesi halka biçiminde kabuğundan tamamen soyulduğunda (halkalama) zamanla ölmesinin fizyolojik açıklaması nedir?","steps":[{"t":"Soyulan kısım","a":"Floem dahil","d":"Halkalamada kabuk ve onun iç kısmındaki ikincil floem tabakası da uzaklaştırılır. Floem yapraklarda üretilen organik besini aşağıya taşıyan dokudur."},{"t":"Besin akışı","a":"Kesilir","d":"Floem koptuğunda yapraklardaki besin gövdenin alt kısmına ve köklere ulaşamaz. Kökler enerji ve besin alamadığından zamanla işlev göremez."},{"t":"Sonuç","a":"Ağaç ölür","d":"Kökler beslenemeyip öldüğünde su ve mineral alımı da durur. Bu nedenle ağaç bir süre sonra tamamen kurur."}],"ans":"Floem koptuğundan besin köklere gidemez, kökler ölür ve ağaç kurur"},{"q":"Tropik bölgelerde yetişen bazı ağaçlarda belirgin yıllık halkaların görülmemesi neyle açıklanır?","steps":[{"t":"Halka oluşum koşulu","a":"Mevsim farkı","d":"Yıllık halkalar ilkbahar ve yaz odunu arasındaki büyüme hızı farkından kaynaklanır. Belirgin mevsim değişimi bu farkı oluşturur."},{"t":"Tropik iklim","a":"Sabit koşullar","d":"Tropik bölgelerde sıcaklık ve yağış yıl boyu birbirine yakındır, belirgin mevsim farkı yoktur. Bu yüzden kambiyum yıl boyu benzer hızda hücre üretir."},{"t":"Sonuç","a":"Halkasız büyüme","d":"Büyüme hızında belirgin değişiklik olmadığından açık-koyu odun ayrımı oluşmaz. Bu nedenle belirgin yıllık halkalar gözlenmez."}],"ans":"Belirgin mevsim farkı olmadığından açık-koyu odun ayrımı, dolayısıyla halka oluşmaz"},{"q":"İkincil büyüme gösteren bir gövdede \"kabuk\" terimi anatomik olarak hangi dokuları kapsar?","steps":[{"t":"Kabuğun sınırı","a":"Kambiyum dışı","d":"Anatomide kabuk, vasküler kambiyumun dışında kalan tüm dokuları ifade eder. Yani odun (ksilem) kabuğa dahil değildir."},{"t":"İç kabuk","a":"İkincil floem","d":"Kabuğun iç kısmı canlı ikincil floemden oluşur ve besin taşır. Buna iç kabuk veya canlı kabuk denir."},{"t":"Dış kabuk","a":"Periderm","d":"Kabuğun dış kısmı ise periderm ve birikmiş ölü dokulardan oluşur. Bu dış kabuk koruma görevi görür."}],"ans":"Kambiyum dışındaki tüm dokular: ikincil floem ve periderm"},{"q":"Mantar kambiyumu (fellojen) ile vasküler kambiyumun köken ve ürettikleri açısından farkı nedir?","steps":[{"t":"Vasküler kambiyum","a":"İletim üretir","d":"Vasküler kambiyum iletim demetleri kökenli bir yanal meristemdir. İçe ksilem dışa floem üreterek iletim dokularını çoğaltır."},{"t":"Fellojen kökeni","a":"Korteks/floem","d":"Mantar kambiyumu genellikle korteks ya da floem parankimasındaki hücrelerin yeniden bölünme kazanmasıyla oluşur. Gövdenin daha dışında yer alır."},{"t":"Fellojen ürünü","a":"Periderm","d":"Fellojen dışa mantar (fellem), içe felloderm üreterek peridermi oluşturur. Yani iletim değil koruyucu doku üretir."}],"ans":"Vasküler kambiyum iletim dokusu, fellojen ise koruyucu periderm üretir"},{"q":"İkincil ksilemde bulunan öz ışınları (radyal parankima) hangi işlevi görür?","steps":[{"t":"Yapı","a":"Radyal hücreler","d":"Öz ışınları, odun içinde merkezden çevreye doğru ışınsal uzanan parankima hücre sıralarıdır. Kambiyum tarafından üretilirler."},{"t":"İşlev","a":"Yatay taşıma","d":"Bu ışınlar su, mineral ve besinin gövde içinde yatay (enine) yönde taşınmasını sağlar. Böylece merkez ile çevre arasında madde alışverişi olur."},{"t":"Ek görev","a":"Depolama","d":"Öz ışınları aynı zamanda besin depolama görevi de görür. Canlı parankima hücreleri olduklarından nişasta gibi maddeleri biriktirebilir."}],"ans":"Maddelerin gövdede yatay (enine) taşınmasını ve depolanmasını sağlar"},{"q":"İklim bilimciler eski ağaç gövdelerindeki yıllık halkaların kalınlıklarını inceleyerek geçmiş iklim hakkında bilgi edinebilir. Bunun bilimsel dayanağı nedir?","steps":[{"t":"Halka-büyüme ilişkisi","a":"Koşula bağlı","d":"Bir yılda oluşan halkanın genişliği o yılki büyüme miktarına bağlıdır. Büyüme ise su, sıcaklık ve ışık gibi iklim koşullarından etkilenir."},{"t":"Geniş ve dar halka","a":"İyi-kötü yıl","d":"Yağışlı ve elverişli yıllarda geniş halkalar, kurak veya olumsuz yıllarda dar halkalar oluşur. Bu sayede her halka bir yılın koşulunu yansıtır."},{"t":"Bilim dalı","a":"Dendrokronoloji","d":"Halka kalınlıklarını inceleyerek geçmiş iklimi araştıran bu yönteme dendrokronoloji denir. Böylece yüzyıllar öncesinin iklim kayıtları çıkarılabilir."}],"ans":"Halka kalınlığı o yılın iklim koşulunu yansıtır (dendrokronoloji)"}],"zor":[{"q":"Çift çenekli bir gövdede ikincil büyümenin başlaması için fasiküler ve interfasiküler kambiyumun nasıl bir bütün oluşturduğunu adım adım açıklayınız.","steps":[{"t":"Başlangıç","a":"Demet içi kambiyum","d":"Birincil yapıda her iletim demetinde ksilem ile floem arasında fasiküler (demet içi) kambiyum bulunur. Bu, demetlere özgü ayrı ayrı meristem bölgeleridir."},{"t":"Aktivasyon","a":"Parankima bölünür","d":"İkincil büyüme başlarken demetler arasındaki parankima hücreleri bölünme yeteneği kazanır. Bu hücreler interfasiküler (demetler arası) kambiyumu oluşturur."},{"t":"Birleşme","a":"Halka tamamlanır","d":"Fasiküler ve interfasiküler kambiyum yanlamasına birleşerek kesintisiz bir kambiyum halkası meydana getirir. Artık gövde çevresi boyunca tam bir silindir oluşur."},{"t":"Üretim","a":"Çift yönlü","d":"Bu kambiyum halkası içe ikincil ksilem, dışa ikincil floem üreterek gövdeyi her yönde kalınlaştırır. Böylece düzenli ikincil büyüme başlar."}],"ans":"Fasiküler ve interfasiküler kambiyum birleşerek tam halka oluşturur ve içe ksilem dışa floem üretir"},{"q":"Bir ağaçta ikincil ksilem hacmi neden ikincil floem hacminden çok daha fazladır ve bu durum gövdenin uzun vadeli yapısını nasıl belirler?","steps":[{"t":"Üretim oranı","a":"Ksilem ağırlıklı","d":"Vasküler kambiyum içe doğru, dışa doğru ürettiğinden çok daha fazla hücre üretir. Bu yüzden ikincil ksilem her yıl gövdede belirgin şekilde birikir."},{"t":"Floemin kaderi","a":"Ezilir","d":"İkincil floem hem az üretilir hem de dışa itildikçe ezilip parçalanır. Eski floem işlevini yitirir ve kabuğun ölü kısmına katılır."},{"t":"Ksilemin birikimi","a":"Kalıcı odun","d":"Ksilem ligninli sert çeperleri sayesinde ezilmeden birikir ve odunu oluşturur. Yıllar geçtikçe odun gövdenin neredeyse tüm kütlesini kaplar."},{"t":"Uzun vadeli sonuç","a":"Odun gövde","d":"Sonuçta yaşlı bir ağacın gövdesi büyük oranda birikmiş ikincil ksilemden (odun) oluşur. İnce floem ve periderm yalnızca dış kabuğu meydana getirir."}],"ans":"Ksilem daha çok üretilip ezilmediğinden birikir; gövde zamanla büyük oranda odundan oluşur"},{"q":"Ilıman bölge bir ağacında yıllık halka oluşumunu kambiyum aktivitesi ve hücre özellikleriyle ilişkilendirerek açıklayınız.","steps":[{"t":"İlkbahar dönemi","a":"Hızlı bölünme","d":"İlkbaharda su ve sıcaklık elverişli olduğundan kambiyum hızlı bölünür. Üretilen ksilem hücreleri büyük çaplı ve ince çeperlidir, bu da açık renkli ilkbahar odununu oluşturur."},{"t":"Yaz dönemi","a":"Yavaş bölünme","d":"Yaz sonuna doğru su azalır ve büyüme yavaşlar. Üretilen hücreler küçük çaplı, kalın çeperli ve sıkı dizilidir, bu da koyu renkli yaz odununu oluşturur."},{"t":"Kış durakla","a":"Kambiyum durur","d":"Kış aylarında kambiyum aktivitesi durur, hücre üretimi olmaz. Ertesi ilkbaharda yeniden başlayan üretim önceki yaz odunuyla keskin bir sınır oluşturur."},{"t":"Halka","a":"Yıllık iz","d":"Açık ilkbahar odunu ile koyu yaz odununun oluşturduğu çift, bir yıllık halkayı temsil eder. Bu halkalar sayılarak ağacın yaşı belirlenebilir."}],"ans":"İlkbaharda geniş açık, yazın dar koyu odun üretilir; her açık-koyu çift bir yıllık halkadır"},{"q":"Öz odunun oluşum süreci ve diri odundan farkını hücresel düzeyde açıklayınız.","steps":[{"t":"Diri odun","a":"Genç ksilem","d":"Diri odun, kambiyuma yakın yeni oluşmuş ksilemdir ve canlı parankima hücreleri içerir. İletim borularının açık olması sayesinde su ve mineral taşır."},{"t":"Yaşlanma","a":"İç kısım","d":"Yıllar geçtikçe gövdenin iç kısımlarındaki ksilem yaşlanır ve parankima hücreleri ölür. İletim borularına tilloz adı verilen tıkaçlar girer ve borular tıkanır."},{"t":"Madde birikimi","a":"Reçine-tanen","d":"Bu bölgede reçine, tanen ve diğer maddeler birikir, bu da odunu koyulaştırır ve dayanıklı kılar. İletim işlevi artık tamamen durmuştur."},{"t":"Sonuç","a":"İşlev ayrımı","d":"Böylece merkezde iletim yapmayan koyu öz odun, çevrede iletim yapan açık diri odun oluşur. Öz odun yalnızca mekanik destek sağlar."}],"ans":"İç ksilem yaşlanıp tıkanarak iletim yapmayan öz oduna dönüşür; diri odun ise iletimi sürdürür"},{"q":"Periderm oluşumunu fellojenin köken aldığı yer ve ürettiği üç katmanla birlikte ayrıntılı açıklayınız.","steps":[{"t":"Köken","a":"Korteks/floem","d":"Mantar kambiyumu (fellojen), genellikle epidermis altındaki korteks ya da floem parankimasındaki hücrelerin yeniden meristematik hale gelmesiyle oluşur. Yanal bir meristem olarak halka biçimi alır."},{"t":"Dışa üretim","a":"Fellem","d":"Fellojen dışa doğru fellem (mantar) hücreleri üretir. Bu hücrelerin çeperine süberin birikerek su ve gaz geçirmez koruyucu bir tabaka oluşturur."},{"t":"İçe üretim","a":"Felloderm","d":"Fellojen içe doğru ise canlı felloderm hücreleri üretir. Bu hücreler parankima benzeri olup destek ve depolama görevi görür."},{"t":"Bütün","a":"Periderm","d":"Fellem, fellojen ve felloderm birlikte peridermi oluşturur. Periderm, yırtılan epidermisin yerini alarak gövdenin yeni koruyucu örtüsü olur."}],"ans":"Fellojen korteksten oluşur; dışa fellem, içe felloderm üreterek peridermi meydana getirir"},{"q":"Lentisellerin yapısı ve stomalardan farkını gaz alışverişi açısından karşılaştırarak açıklayınız.","steps":[{"t":"Stoma","a":"Genç dokuda","d":"Stomalar epidermiste bulunan, iki bekçi hücresiyle açılıp kapanabilen aktif gözeneklerdir. Yaprak ve genç gövdelerde gaz alışverişini düzenler."},{"t":"Peridermin sorunu","a":"Geçirimsizlik","d":"İkincil büyümede epidermis yırtılır ve yerini süberinli, geçirimsiz periderm alır. Bu durumda stoma kalmadığından iç dokular hava ile temas edemez."},{"t":"Lentisel yapısı","a":"Gevşek doku","d":"Lentiseller, peridermdeki gevşek dizilimli, bol hücre arası boşluğu olan tamamlayıcı dokulardır. Genellikle eski stomaların altında oluşur ve kabartılı görünür."},{"t":"Fark","a":"Pasif-aktif","d":"Stomalar açılıp kapanarak aktif düzenleme yaparken, lentiseller açılıp kapanamaz ve pasif gaz geçişine izin verir. Her ikisi de gaz alışverişi sağlar ancak mekanizmaları farklıdır."}],"ans":"Stoma aktif açılıp kapanır, lentisel pasif geçiş sağlar; lentisel kalınlaşmış gövdede stomanın işlevini görür"},{"q":"Tek çenekli bir bitki olan bambu çok hızlı uzayıp belli bir kalınlığa ulaşır ama çınar gibi gerçek ikincil büyüme göstermez. Bu durumu anatomik olarak açıklayınız.","steps":[{"t":"Bambu uzaması","a":"Birincil büyüme","d":"Bambunun hızlı boy uzaması boğum aralarındaki interkalar (ara) meristemlerin etkinliğiyle olur. Bu birincil büyümedir ve enine kalınlaşma sağlamaz."},{"t":"Demet dizilimi","a":"Dağınık","d":"Tek çenekli olarak bambuda iletim demetleri gövde içinde dağınık dizilmiştir. Bu demetler arasında düzenli bir kambiyum halkası oluşamaz."},{"t":"Kambiyum eksikliği","a":"Vasküler yok","d":"Bambuda gerçek vasküler kambiyum bulunmadığından içe odun dışa soymuk üretemez. Bu nedenle çınardaki gibi yıllık halkalı kalınlaşma görülmez."},{"t":"Çap durumu","a":"Erken belirlenir","d":"Bambunun çapı genç sürgün aşamasında belirlenir, sonradan belirgin biçimde artmaz. Sertlik artışı çeperlerin lignifikasyonuyla olur, kambiyumla değil."}],"ans":"Bambu tek çenekli olup kambiyumu yoktur; uzaması birincil büyümedir, gerçek ikincil büyüme göstermez"},{"q":"Bir ağaca yaklaşık göğüs hizasında bir çivi çakıldığında, ağaç yıllarca büyüse bile çivinin yerden yüksekliğinin değişmemesinin nedeni nedir?","steps":[{"t":"Uzamanın yeri","a":"Sürgün ucu","d":"Ağacın boyca uzaması yalnızca sürgün ve kök uçlarındaki apikal meristemlerde gerçekleşir. Gövdenin orta kısımlarındaki olgun hücreler artık uzamaz."},{"t":"Gövde davranışı","a":"Yalnızca kalınlaşır","d":"Çivinin çakıldığı bölge yalnızca vasküler kambiyum sayesinde enine kalınlaşır. Bu bölgede dikey (boyca) bir uzama olmaz."},{"t":"Çivinin durumu","a":"Aynı yükseklik","d":"Boyca uzama yukarıda gerçekleştiğinden çivinin yerden yüksekliği değişmez. Ağaç daha boylu hale gelse de çivi aynı seviyede kalır."},{"t":"Gözlemlenebilir etki","a":"Çivi gömülür","d":"Yıllar içinde gövde kalınlaştıkça çivi çevresindeki odun büyüdüğü için çivi gövdeye gömülebilir. Ancak yere olan uzaklığı sabit kalır."}],"ans":"Boyca uzama yalnızca uç meristemlerde olur; gövdenin o noktası sadece kalınlaşır, yükselmez"},{"q":"Bazı ağaçlarda odunun büyük kısmı destek görevi görürken iletimi yalnızca dar bir dış bölge yapar. Bu yapı ağaca hangi avantajı sağlar?","steps":[{"t":"İletim bölgesi","a":"Dış diri odun","d":"Su ve mineral iletimi yalnızca dıştaki canlı diri odunda gerçekleşir. Bu bölge kambiyuma yakın, genç ve açık iletim borularına sahiptir."},{"t":"Destek bölgesi","a":"İç öz odun","d":"Merkezdeki geniş öz odun iletim yapmaz ancak ligninli kalın çeperleriyle güçlü mekanik destek sağlar. Reçine ve tanen birikimi onu çürümeye dirençli kılar."},{"t":"Avantaj 1","a":"Dayanıklılık","d":"İç odunun çürümeye dirençli olması ağacın gövdesinin uzun yıllar ayakta kalmasını sağlar. Bu, boylu ağaçların yıkılmadan büyüyebilmesini mümkün kılar."},{"t":"Avantaj 2","a":"Verimli iletim","d":"Yaşlanan iletim boruları öz oduna aktarılarak işlevsel iletim sürekli yenilenir. Böylece ağaç hem güçlü kalır hem de etkili su taşımayı sürdürür."}],"ans":"Sağlam destek ile sürekli yenilenen iletim bir arada bulunur; ağaç hem güçlü kalır hem boylanabilir"},{"q":"Yıllık halkaların kalınlığı, yönü ve sıklığından geçmiş çevre koşulları çıkarılabilir. Üç farklı durumun halkalara yansımasını açıklayınız.","steps":[{"t":"Kurak yıl","a":"Dar halka","d":"Su kıtlığı olan yıllarda kambiyum daha az hücre üretir ve dar bir halka oluşur. Birbiri ardına dar halkalar kurak dönemleri gösterir."},{"t":"Bol su yılı","a":"Geniş halka","d":"Yağışlı ve elverişli yıllarda büyüme hızlanır ve geniş halka oluşur. Geniş halkalar verimli yılların kaydını tutar."},{"t":"Eğik halkalar","a":"Tek yönlü etki","d":"Halkaların bir tarafta daha geniş olması, o yönden gelen sürekli rüzgar ya da eğimde ışık gibi tek yönlü etkilere işaret eder. Tepki odunu denilen asimetrik büyüme oluşur."},{"t":"Yorum","a":"İklim arşivi","d":"Tüm bu izler birleştirildiğinde gövde adeta bir iklim arşivine dönüşür. Dendrokronoloji bu izleri okuyarak geçmiş çevre koşullarını yeniden kurar."}],"ans":"Dar halka kuraklık, geniş halka bol su, asimetrik halka tek yönlü etkiyi gösterir"},{"q":"İkincil büyüme sırasında kabuğun zamanla çatlamasının ve dökülmesinin anatomik nedenini açıklayınız.","steps":[{"t":"İç büyüme","a":"Çap artışı","d":"Vasküler kambiyum her yıl içe odun üreterek gövde çapını sürekli artırır. Bu, dıştaki dokulara doğru büyüyen bir basınç oluşturur."},{"t":"Periderm esneksizliği","a":"Ölü hücreler","d":"Dış peridermi oluşturan mantar hücreleri ölü ve esnemeyen yapıdadır. Artan iç çapa uyum sağlayamadıkları için gerilirler."},{"t":"Çatlama","a":"Yüzeyde kırılma","d":"Esneyemeyen dış kabuk artan basınç altında çatlar ve yüzeyde tipik kabuk desenleri oluşur. Her ağaç türünün kabuk çatlama deseni karakteristiktir."},{"t":"Yenilenme","a":"Yeni periderm","d":"İçte fellojen yeni periderm tabakaları üretirken dıştaki eski ölü dokular kopup dökülür. Böylece kabuk sürekli yenilenirken eski kısımlar atılır."}],"ans":"İç çap artarken esnemeyen ölü periderm gerilip çatlar ve eski tabakalar dökülür"},{"q":"Bir botanikçi tek çenekli bir bitki kesitiyle çift çenekli odunsu bir bitki kesitini karşılaştırıyor. İkincil büyüme açısından üç temel farkı belirtiniz.","steps":[{"t":"Demet dizilimi","a":"Dağınık-halka","d":"Tek çeneklilerde iletim demetleri dağınık, çift çeneklilerde düzenli bir halka şeklinde dizilir. Bu dizilim kambiyum oluşumunu belirleyen ilk farktır."},{"t":"Kambiyum varlığı","a":"Yok-var","d":"Tek çeneklilerde demetlerde genellikle kambiyum yoktur, çift çeneklilerde ksilem-floem arasında kambiyum bulunur. Kambiyum ikincil büyümenin temel koşuludur."},{"t":"Büyüme türü","a":"Birincil-ikincil","d":"Tek çenekliler genellikle yalnızca birincil büyümeyle gelişirken çift çenekliler ikincil büyümeyle kalınlaşır. Bu nedenle odunsu gövde çoğunlukla çift çeneklilerde görülür."},{"t":"Sonuç","a":"Yapısal fark","d":"Sonuçta çift çenekli odunsu bitki yıllık halkalı kalın gövde oluştururken tek çenekli genellikle bunu yapamaz. Palmiye gibi istisnalar kambiyum dışı mekanizmalarla sınırlı çap artışı gösterir."}],"ans":"Demet dizilimi (dağınık-halka), kambiyum (yok-var) ve büyüme türü (birincil-ikincil) farklıdır"},{"q":"İkincil floemin sürekli yenilenmesine karşın ikincil ksilemin yıllarca biriken yapısı, bir ağacın yaşının neden ksilemden okunabildiğini nasıl açıklar?","steps":[{"t":"Floemin durumu","a":"Korunmaz","d":"İkincil floem dışa doğru itildikçe ezilir ve eski floem işlevini yitirerek kabuğun ölü kısmına karışır. Bu yüzden geçmiş yılların floem kaydı korunmaz."},{"t":"Ksilemin durumu","a":"Birikir","d":"İkincil ksilem ligninli sert çeperleri sayesinde ezilmeden gövdede birikir. Her yılın ürettiği odun kalıcı bir katman olarak kalır."},{"t":"Halka kaydı","a":"Ksilemde","d":"Birbiri ardına biriken odun katmanları yıllık halkaları oluşturur. Bu halkalar yalnızca ksilemde korunduğundan yaş bilgisi orada saklanır."},{"t":"Sonuç","a":"Ksilemden okuma","d":"Floemde geçmiş kayıt kalmadığından ağacın yaşı yalnızca ksilemdeki halkalardan okunabilir. Halkalar sayılarak yaklaşık yaş belirlenir."}],"ans":"Floem ezilip kaybolur, ksilem birikip halka oluşturur; bu yüzden yaş ksilemden okunur"},{"q":"Soğuk iklim bir ağacının gövdesinde reaksiyon (tepki) odunu nasıl ve neden oluşur?","steps":[{"t":"Mekanik etki","a":"Eğilme baskısı","d":"Eğimli arazide veya sürekli rüzgar altında büyüyen ağaçların gövdesi tek yönlü mekanik baskıya maruz kalır. Bu baskı kambiyumun bir tarafta farklı çalışmasına neden olur."},{"t":"Asimetrik üretim","a":"Tek yön fazla","d":"Kambiyum baskıya uğrayan veya destek gereken yönde daha fazla ve farklı yapıda odun üretir. Bu yüzden yıllık halkalar o tarafta daha geniş ve eksantrik olur."},{"t":"Odun türü","a":"Basınç-gerilme","d":"İğne yapraklılarda basınç tarafında basınç odunu, geniş yapraklılarda gerilme tarafında gerilme odunu oluşur. Bu odunlar normal odundan farklı hücre yapısına sahiptir."},{"t":"İşlev","a":"Dik tutma","d":"Reaksiyon odunu gövdeyi düzeltmeye veya dik konumda tutmaya çalışır. Böylece ağaç olumsuz mekanik koşullara karşı dengesini korur."}],"ans":"Tek yönlü mekanik baskıya tepki olarak kambiyum asimetrik özel odun üretir, gövdeyi dik tutar"},{"q":"Bir meyve ağacına aşı yapıldığında anaç ile kalemin başarıyla kaynaşması hangi dokunun uyumuna bağlıdır ve neden?","steps":[{"t":"Aşının amacı","a":"İki parça birleşir","d":"Aşıda bir bitkinin sürgünü (kalem) başka bir bitkinin gövdesine (anaç) eklenir. Amaç iki dokunun kaynaşıp tek bir iletim sistemi oluşturmasıdır."},{"t":"Kritik doku","a":"Kambiyum","d":"Başarılı kaynaşmanın anahtarı anaç ve kalemin vasküler kambiyum tabakalarının karşı karşıya getirilmesidir. Kambiyum bölünebilen meristem olduğundan yeni dokular üretir."},{"t":"Kaynaşma","a":"Ortak doku","d":"Karşılıklı kambiyumlar bölünerek köprü oluşturan kallus ve yeni iletim dokuları üretir. Böylece ksilem ve floem bağlantısı kurulur."},{"t":"Sonuç","a":"Süreklilik","d":"İletim demetleri birleştiğinde su ve besin anaç ile kalem arasında akabilir. Kambiyumlar uyumsuz hizalanırsa kaynaşma başarısız olur."}],"ans":"Anaç ve kalemin vasküler kambiyumlarının uyumlu birleşmesine bağlıdır, çünkü yeni iletim dokuları kambiyumdan üretilir"}]}}};
